    @staticmethod
    def _scenario_divergence_views(pattern_memory: dict, playbook_views: dict) -> tuple[dict, dict, dict]:
        divergence_review_state = playbook_views["divergence_review_state"] or {}
        scenario_family_fit_state = playbook_views.get("scenario_family_fit_state", {}) or {}
        evidence_confidence_state = playbook_views.get("evidence_confidence_state", {}) or {}
        presentation_weight, presentation_label = AuraliteReportingService._evidence_presentation_weight(
            scenario_family_fit_state=scenario_family_fit_state,
            evidence_confidence_state=evidence_confidence_state,
        )
        operator_divergence = divergence_review_state.get("operator_divergence_evidence", {}) or {}
        divergence_lines = list((operator_divergence.get("compact_lines") or [])[:3])
        if presentation_label != "full_strength_fit":
            qualifier = (
                "Family fit is weak; treat divergence history as loose guidance."
                if presentation_label == "softened_for_weak_fit"
                else "Family fit is mixed/moderate; divergence evidence is informative but qualified."
            )
            divergence_lines = [qualifier] + divergence_lines
        divergence_review_state["operator_divergence_evidence"] = {
            **operator_divergence,
            "compact_lines": divergence_lines[:3],
            "presentation_weight": presentation_weight,
            "presentation_label": presentation_label,
        }
        divergence_views = AuraliteReportingService._divergence_comparison_views(divergence_review_state)
        operator_intervention_review_evidence = AuraliteReportingService._operator_intervention_review_evidence(
            {
                "family_level_intervention_review": pattern_memory.get("family_level_intervention_review", {}),
                "leverage_vs_regime_separation": divergence_views["leverage_vs_regime_separation"],
                "threshold_momentum_sensitivity": divergence_views["threshold_momentum_sensitivity"],
                "scenario_family_fit_state": scenario_family_fit_state,
                "evidence_confidence_state": evidence_confidence_state,
            }
        )
        return divergence_review_state, divergence_views, operator_intervention_review_evidence

    @staticmethod
    def _evidence_presentation_weight(scenario_family_fit_state: dict, evidence_confidence_state: dict) -> tuple[float, str]:
        fit_label = scenario_family_fit_state.get("fit_label", "weak_family_fit")
        multiplier = float(evidence_confidence_state.get("family_fit_multiplier", 0.54))
        if fit_label == "strong_family_fit":
            return 1.0, "full_strength_fit"
        if fit_label == "moderate_family_fit":
            return round(max(0.78, min(0.92, multiplier)), 3), "softened_for_moderate_fit"
        if fit_label == "mixed_or_unstable_family_fit":
            return round(max(0.58, min(0.76, multiplier)), 3), "softened_for_mixed_fit"
        return round(max(0.42, min(0.62, multiplier)), 3), "softened_for_weak_fit"

    @staticmethod
    def _operator_family_fit_confidence_lines(scenario_family_fit_state: dict, evidence_confidence_state: dict) -> list[str]:
        fit_label = scenario_family_fit_state.get("fit_label", "weak_family_fit")
        fit_score = float(scenario_family_fit_state.get("fit_score", 0.0))
        historical_confidence = (evidence_confidence_state.get("historical_comparison_confidence") or {}).get("label", "low_bounded_confidence")
        reuse_state = (evidence_confidence_state.get("historical_evidence_reuse_state") or {})
        reuse_label = reuse_state.get("reuse_label", "low_reuse_historical_context")
        reuse_fragment = f"reuse={reuse_label}"
        if fit_label == "strong_family_fit":
            return [f"Strong family fit ({fit_score:.2f}); historical evidence is likely reusable with bounded confidence ({historical_confidence}, {reuse_fragment})."]
        if fit_label == "moderate_family_fit":
            return [f"Moderate family fit ({fit_score:.2f}); use historical evidence as guided context ({historical_confidence}, {reuse_fragment})."]
        if fit_label == "mixed_or_unstable_family_fit":
            return [f"Mixed family fit ({fit_score:.2f}); similar patterns exist but separation is material ({historical_confidence}, {reuse_fragment})."]
        return [f"Weak family fit ({fit_score:.2f}); treat history as loose guidance only ({historical_confidence}, {reuse_fragment})."]

    @staticmethod
    def _operator_novelty_outlier_evidence(
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        scenario_family_fit_state: dict,
        evidence_confidence_state: dict,
    ) -> dict:
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        novelty_score = float(scenario_novelty_state.get("novelty_score", 0.0))
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        primary = hybrid_family_state.get("primary_family")
        secondary = hybrid_family_state.get("secondary_family")
        fit_label = scenario_family_fit_state.get("fit_label", "weak_family_fit")
        reuse_label = ((evidence_confidence_state.get("historical_evidence_reuse_state") or {}).get("reuse_label")) or "partial_reuse_historical_context"
        lines = []
        if novelty_label == "high_novelty":
            lines.append(f"Weak family match outlier context: {novelty_label} ({novelty_score:.2f}).")
        elif novelty_label == "moderate_novelty":
            lines.append(f"Bounded novelty is active ({novelty_score:.2f}); compare against family history with caution.")
        else:
            lines.append(f"Novelty remains low ({novelty_score:.2f}); family comparisons are relatively stable.")
        if hybrid_label == "two_family_hybrid" and secondary:
            lines.append(f"Run is a hybrid between {primary} and {secondary}.")
        elif hybrid_label in {"mixed_family_pull", "unstable_family_identity"} and secondary:
            lines.append(f"Family identity is mixed: {primary} anchor with pull toward {secondary}.")
        elif hybrid_label == "weak_single_family_anchor":
            lines.append("Single-family anchor is weak; avoid strict one-family interpretation.")
        lines.append(f"Historical evidence should be treated as {reuse_label}.")
        return {
            "novelty_label": novelty_label,
            "hybrid_label": hybrid_label,
            "fit_label": fit_label,
            "reuse_label": reuse_label,
            "primary_family": primary,
            "secondary_family": secondary,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _backfill_divergence_review_state(pattern_memory: dict) -> dict:
        existing = pattern_memory.get("divergence_review_state", {})
        if existing:
            return existing
        return {
            "archetype_divergence_signals": [],
            "similar_archetype_comparison_signals": {
                "matched_family": ((pattern_memory.get("scenario_archetype_memory") or {}).get("nearest_recurring_archetype_family")),
                "same_archetype_family": False,
                "active_signals": [],
                "summary_label": "no_material_separation_detected",
            },
            "leverage_vs_regime_separation": {
                "dominant_source_label": "mixed_source_divergence",
                "traction_source_label": "mixed_source_traction",
                "leverage_source_score": 0.0,
                "regime_drift_source_score": 0.0,
                "score_spread": 0.0,
                "collapse_override_flags": {
                    "leverage_collapse_case": False,
                    "regime_override_case": False,
                },
                "evidence": {},
            },
            "threshold_momentum_sensitivity": {
                "high_threshold_sensitivity": {"active": False},
                "fragile_momentum_sensitivity": {"active": False},
                "durable_momentum_support": {"active": False},
                "local_only_sensitivity": {"active": False},
                "traction_window_review": {
                    "label": "mixed_window_response",
                    "traction_holding": False,
                    "traction_weakened": False,
                    "traction_stayed_local": False,
                },
                "summary_label": "mixed_sensitivity",
            },
            "leverage_point_divergence_signals": {},
            "gain_durability_review_signals": {},
            "operator_divergence_evidence": {
                "matched_family": (
                    (pattern_memory.get("scenario_archetype_memory") or {}).get("nearest_recurring_archetype_family")
                ),
                "current_archetype": (
                    (pattern_memory.get("scenario_archetype_memory") or {}).get("current_scenario_archetype")
                ),
                "compact_lines": [],
            },
            "historical_divergence_evidence_lines": [],
            "review_metadata": {},
        }

