    @staticmethod
    def _nearest_analog_state(
        scenario_outcome: dict,
        insights: list[dict],
        scenario_archetype_memory: dict,
        regime_family_memory: dict,
        leverage_patterns: dict,
        weak_vs_broad_review_signals: dict,
    ) -> dict:
        current_archetype = scenario_archetype_memory.get("current_scenario_archetype")
        nearest_family = scenario_archetype_memory.get("nearest_recurring_archetype_family")
        recurring = scenario_archetype_memory.get("recurring_scenario_archetypes") or []
        recurring_counts = {
            str(item.get("scenario_archetype", "")): int(item.get("count", 0))
            for item in recurring
            if item.get("scenario_archetype")
        }
        weak_count = int((weak_vs_broad_review_signals.get("repeated_weak_traction") or {}).get("count", 0))
        local_only_count = int((weak_vs_broad_review_signals.get("repeated_local_only_movement") or {}).get("count", 0))
        broad_count = int((weak_vs_broad_review_signals.get("repeated_broader_regime_improvement") or {}).get("count", 0))
        leverage_recurrence = int((scenario_outcome.get("intervention_learning_signals", {}) or {}).get("sample_count", 0))

        insight_matches = 0
        scenario_name_matches = 0
        active_scenario_name = str(scenario_outcome.get("scenario_name", ""))
        for insight in insights[-16:]:
            tags = insight.get("filter_tags", {}) or {}
            if tags.get("scenario_name") == active_scenario_name:
                scenario_name_matches += 1
            conditions = insight.get("conditions", {}) or {}
            if current_archetype and conditions:
                phase_value = str(((conditions.get("city_regime_state") or {}).get("phase")) or "")
                if phase_value and regime_family_memory.get("current_family", "").replace("_family", "") in phase_value:
                    insight_matches += 1

        strongest_key = current_archetype or nearest_family or "mixed_transition_with_stalled_improvement"
        strongest_count = recurring_counts.get(strongest_key, 0)
        secondary_candidates = [
            row
            for row in AuraliteReportingService._bounded_archetype_candidates(recurring=recurring, limit=4)
            if row.get("scenario_archetype") != strongest_key
        ]
        secondary = secondary_candidates[0] if secondary_candidates else {}
        secondary_key = secondary.get("scenario_archetype")
        secondary_count = int(secondary.get("recurrence_count", secondary.get("count", 0))) if secondary_key else 0

        signal_score = (
            min(0.42, strongest_count * 0.16)
            + min(0.2, secondary_count * 0.08)
            + min(0.14, scenario_name_matches * 0.03)
            + min(0.08, insight_matches * 0.02)
            + (0.06 if broad_count > local_only_count else 0.0)
            + min(0.08, leverage_recurrence * 0.02)
            - min(0.16, weak_count * 0.04)
        )
        signal_score = round(max(0.0, min(1.0, signal_score)), 3)

        if signal_score >= 0.66 and strongest_count >= 2:
            match_label = "strongest_prior_analog"
        elif signal_score >= 0.46 and secondary_count > 0:
            match_label = "secondary_prior_analog"
        elif signal_score >= 0.24:
            match_label = "weak_analog_match"
        else:
            match_label = "no_useful_analog"

        compact_lines = [
            f"Nearest analog: {match_label} (score {signal_score:.2f}) within {regime_family_memory.get('current_family', 'mixed_transition_family')}.",
        ]
        if strongest_key:
            compact_lines.append(f"Closest prior run pattern: {strongest_key} (recurrence {strongest_count}).")
        if secondary_key:
            compact_lines.append(f"Secondary analog candidate: {secondary_key} (recurrence {secondary_count}).")
        elif match_label in {"weak_analog_match", "no_useful_analog"}:
            compact_lines.append("No stable secondary analog surfaced in bounded history windows.")

        return {
            "match_label": match_label,
            "match_score": signal_score,
            "strongest_prior_analog": {
                "scenario_archetype": strongest_key,
                "recurrence_count": strongest_count,
                "same_as_current_archetype": bool(current_archetype and strongest_key == current_archetype),
            },
            "secondary_prior_analog": {
                "scenario_archetype": secondary_key,
                "recurrence_count": secondary_count,
            },
            "weak_match_signals": {
                "repeated_weak_traction_count": weak_count,
                "repeated_local_only_count": local_only_count,
                "repeated_broader_improvement_count": broad_count,
                "scenario_name_match_count": scenario_name_matches,
            },
            "no_useful_analog": match_label == "no_useful_analog",
            "compact_lines": compact_lines[:3],
        }

    @staticmethod
    def _bounded_archetype_candidates(recurring: list[dict], limit: int = 4) -> list[dict]:
        candidates = []
        for row in recurring[: max(1, limit)]:
            archetype = row.get("scenario_archetype")
            if not archetype:
                continue
            candidates.append(
                {
                    "scenario_archetype": archetype,
                    "recurrence_count": int(row.get("count", row.get("recurrence_count", 0))),
                }
            )
        return candidates

    @staticmethod
    def _analog_cluster_state(
        nearest_analog_state: dict,
        scenario_archetype_memory: dict,
        weak_vs_broad_review_signals: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        saved_insights: list[dict],
    ) -> dict:
        recurring = scenario_archetype_memory.get("recurring_scenario_archetypes") or []
        strongest = nearest_analog_state.get("strongest_prior_analog", {}) or {}
        secondary = nearest_analog_state.get("secondary_prior_analog", {}) or {}
        weak_count = int((weak_vs_broad_review_signals.get("repeated_weak_traction") or {}).get("count", 0))
        local_only_count = int((weak_vs_broad_review_signals.get("repeated_local_only_movement") or {}).get("count", 0))
        broad_count = int((weak_vs_broad_review_signals.get("repeated_broader_regime_improvement") or {}).get("count", 0))
        novelty_score = float(scenario_novelty_state.get("novelty_score", 0.0))
        hybrid_score = float(hybrid_family_state.get("hybrid_score", 0.0))

        bounded_candidates: list[dict] = []
        bounded_candidates.extend(AuraliteReportingService._bounded_archetype_candidates(recurring=recurring, limit=4))
        strongest_name = strongest.get("scenario_archetype")
        if strongest_name and all(item.get("scenario_archetype") != strongest_name for item in bounded_candidates):
            bounded_candidates.append(
                {"scenario_archetype": strongest_name, "recurrence_count": int(strongest.get("recurrence_count", 0))}
            )
        secondary_name = secondary.get("scenario_archetype")
        if secondary_name and all(item.get("scenario_archetype") != secondary_name for item in bounded_candidates):
            bounded_candidates.append(
                {"scenario_archetype": secondary_name, "recurrence_count": int(secondary.get("recurrence_count", 0))}
            )
        bounded_candidates = sorted(
            bounded_candidates,
            key=lambda row: (-int(row.get("recurrence_count", 0)), str(row.get("scenario_archetype", ""))),
        )[:3]
        cluster_size = len([row for row in bounded_candidates if int(row.get("recurrence_count", 0)) > 0])
        support_points = sum(int(row.get("recurrence_count", 0)) for row in bounded_candidates)
        insight_sample_size = min(16, len(saved_insights))
        cluster_score = (
            min(0.5, support_points * 0.12)
            + (0.14 if cluster_size >= 2 else 0.03)
            + min(0.12, broad_count * 0.03)
            + min(0.08, insight_sample_size * 0.01)
            - min(0.2, weak_count * 0.04)
            - min(0.08, local_only_count * 0.02)
            - min(0.14, novelty_score * 0.22)
            - min(0.1, hybrid_score * 0.14)
        )
        cluster_score = round(max(0.0, min(1.0, cluster_score)), 3)

        if cluster_score >= 0.62 and cluster_size >= 2:
            cluster_label = "coherent_analog_cluster"
        elif cluster_score >= 0.42 and cluster_size >= 2:
            cluster_label = "weak_analog_cluster"
        elif cluster_size == 1 and cluster_score >= 0.2:
            cluster_label = "sparse_analog_cluster"
        else:
            cluster_label = "no_useful_analog_cluster"

        lines = [
            f"Analog cluster: {cluster_label} (score {cluster_score:.2f}; size {cluster_size}) from bounded prior-run memory."
        ]
        if bounded_candidates:
            top = ", ".join(
                f"{row.get('scenario_archetype')} x{int(row.get('recurrence_count', 0))}" for row in bounded_candidates[:2]
            )
            lines.append(f"Closest cluster members: {top}.")
        if cluster_label == "no_useful_analog_cluster":
            lines.append("No useful analog cluster surfaced; nearest-analog output should be treated as low-strength context only.")

        return {
            "cluster_label": cluster_label,
            "cluster_score": cluster_score,
            "cluster_size": cluster_size,
            "cluster_members": bounded_candidates,
            "bounded_history_window": 16,
            "basis": {
                "support_points": support_points,
                "weak_traction_count": weak_count,
                "local_only_count": local_only_count,
                "broader_improvement_count": broad_count,
                "insight_sample_size": insight_sample_size,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _analog_agreement_state(
        nearest_analog_state: dict,
        analog_cluster_state: dict,
        partial_analog_support_state: dict,
        divergence_review_state: dict,
        family_level_intervention_review: dict,
    ) -> dict:
        strongest = nearest_analog_state.get("strongest_prior_analog", {}) or {}
        secondary = nearest_analog_state.get("secondary_prior_analog", {}) or {}
        cluster_size = int(analog_cluster_state.get("cluster_size", 0))
        cluster_score = float(analog_cluster_state.get("cluster_score", 0.0))
        partial_label = partial_analog_support_state.get("partial_support_label")
        divergence_count = len(divergence_review_state.get("archetype_divergence_signals") or [])
        separation_count = len((divergence_review_state.get("similar_archetype_comparison_signals") or {}).get("active_signals") or [])
        family_review_label = family_level_intervention_review.get("summary_label", "mixed_family_traction")
        strongest_count = int(strongest.get("recurrence_count", 0))
        secondary_count = int(secondary.get("recurrence_count", 0))
        count_gap = abs(strongest_count - secondary_count)

        agreement_score = (
            min(0.4, cluster_score * 0.52)
            + (0.18 if cluster_size >= 2 else 0.04)
            + (0.12 if count_gap >= 2 else 0.05)
            + (0.1 if family_review_label == "same_family_repeated_traction" else 0.0)
            - min(0.2, divergence_count * 0.05)
            - min(0.12, separation_count * 0.04)
            - (0.08 if partial_label == "analog_mismatch" else 0.0)
        )
        agreement_score = round(max(0.0, min(1.0, agreement_score)), 3)
        if agreement_score >= 0.62 and cluster_size >= 2 and divergence_count == 0:
            agreement_label = "analog_agreement"
        elif agreement_score >= 0.45 and cluster_size >= 2:
            agreement_label = "analog_partial_agreement"
        elif divergence_count > 0 or separation_count > 0:
            agreement_label = "analog_conflict"
        else:
            agreement_label = "analog_ambiguity"

        lines = [f"Analog agreement: {agreement_label} ({agreement_score:.2f}) across bounded analog evidence."]
        if agreement_label == "analog_conflict":
            lines.append("Available analogs pull in different directions across divergence/separation signals.")
        elif agreement_label == "analog_partial_agreement":
            lines.append("Analogs partially align, but secondary or mixed signals still matter.")
        elif agreement_label == "analog_ambiguity":
            lines.append("Analog set is too sparse or mixed to claim clear agreement.")

        return {
            "agreement_label": agreement_label,
            "agreement_score": agreement_score,
            "basis": {
                "cluster_label": analog_cluster_state.get("cluster_label", "no_useful_analog_cluster"),
                "cluster_size": cluster_size,
                "cluster_score": round(cluster_score, 3),
                "divergence_signal_count": divergence_count,
                "separation_signal_count": separation_count,
                "family_review_label": family_review_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _precedent_quality_state(
        analog_cluster_state: dict,
        analog_agreement_state: dict,
        analog_confidence_state: dict,
        partial_analog_support_state: dict,
        nearest_analog_state: dict,
        scenario_archetype_memory: dict,
    ) -> dict:
        cluster_label = analog_cluster_state.get("cluster_label", "no_useful_analog_cluster")
        cluster_score = float(analog_cluster_state.get("cluster_score", 0.0))
        cluster_size = int(analog_cluster_state.get("cluster_size", 0))
        agreement_label = analog_agreement_state.get("agreement_label", "analog_ambiguity")
        agreement_score = float(analog_agreement_state.get("agreement_score", 0.0))
        confidence_label = analog_confidence_state.get("analog_confidence_label", "weak_analog_confidence")
        confidence_score = float(analog_confidence_state.get("analog_confidence_score", 0.0))
        support_label = partial_analog_support_state.get("partial_support_label", "analog_mismatch")
        support_score = float(partial_analog_support_state.get("partial_support_score", 0.0))
        nearest_score = float(nearest_analog_state.get("match_score", 0.0))
        recurring_count = len(scenario_archetype_memory.get("recurring_scenario_archetypes") or [])

        score = (
            min(0.34, cluster_score * 0.34)
            + min(0.22, agreement_score * 0.22)
            + min(0.22, confidence_score * 0.22)
            + min(0.12, support_score * 0.12)
            + min(0.1, nearest_score * 0.1)
        )
        if cluster_label == "coherent_analog_cluster":
            score += 0.1
        elif cluster_label == "no_useful_analog_cluster":
            score -= 0.12
        if agreement_label == "analog_conflict":
            score -= 0.1
        elif agreement_label == "analog_agreement":
            score += 0.08
        if confidence_label in {"weak_analog_confidence", "novelty_limited_analog_confidence"}:
            score -= 0.08
        if support_label == "analog_mismatch":
            score -= 0.04
        if recurring_count <= 1:
            score -= 0.08

        score = round(max(0.0, min(1.0, score)), 3)
        if score >= 0.68 and cluster_size >= 2 and agreement_label == "analog_agreement":
            label = "strong_precedent"
        elif score >= 0.48 and cluster_size >= 2 and agreement_label in {"analog_agreement", "analog_partial_agreement"}:
            label = "moderate_precedent"
        elif score >= 0.26 and cluster_size >= 1:
            label = "weak_precedent"
        else:
            label = "no_useful_precedent"

        lines = [f"Precedent quality: {label} ({score:.2f}) from bounded analog-cluster evidence."]
        if label == "no_useful_precedent":
            lines.append("Analog context exists, but it does not form a reusable precedent lane yet.")
        elif label == "weak_precedent":
            lines.append("A weak precedent lane exists, but reliability remains limited.")

        return {
            "precedent_quality_label": label,
            "precedent_quality_score": score,
            "bounded_lane_available": label in {"strong_precedent", "moderate_precedent", "weak_precedent"},
            "basis": {
                "cluster_label": cluster_label,
                "cluster_size": cluster_size,
                "agreement_label": agreement_label,
                "confidence_label": confidence_label,
                "partial_support_label": support_label,
                "recurring_archetype_count": recurring_count,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _precedent_agreement_state(
        analog_cluster_state: dict,
        analog_agreement_state: dict,
        divergence_review_state: dict,
        family_level_intervention_review: dict,
    ) -> dict:
        agreement_label = analog_agreement_state.get("agreement_label", "analog_ambiguity")
        agreement_score = float(analog_agreement_state.get("agreement_score", 0.0))
        cluster_size = int(analog_cluster_state.get("cluster_size", 0))
        cluster_score = float(analog_cluster_state.get("cluster_score", 0.0))
        divergence_count = len(divergence_review_state.get("archetype_divergence_signals") or [])
        separation_count = len(((divergence_review_state.get("similar_archetype_comparison_signals") or {}).get("active_signals")) or [])
        family_review_label = family_level_intervention_review.get("summary_label", "mixed_family_traction")

        score = (
            min(0.44, agreement_score * 0.44)
            + min(0.24, cluster_score * 0.24)
            + (0.08 if cluster_size >= 2 else 0.0)
            + (0.08 if family_review_label == "same_family_repeated_traction" else 0.02)
            - min(0.22, divergence_count * 0.07)
            - min(0.16, separation_count * 0.05)
        )
        score = round(max(0.0, min(1.0, score)), 3)

        if agreement_label == "analog_agreement" and divergence_count == 0 and separation_count == 0 and score >= 0.62:
            label = "coherent_precedent"
        elif agreement_label in {"analog_agreement", "analog_partial_agreement"} and (divergence_count > 0 or separation_count > 0):
            label = "partially_split_precedent"
        elif agreement_label == "analog_conflict" or (divergence_count >= 2 and separation_count >= 1):
            label = "conflicting_precedent"
        else:
            label = "ambiguous_precedent"

        lines = [f"Precedent agreement: {label} ({score:.2f}) across bounded analog lanes."]
        if label == "partially_split_precedent":
            lines.append("Primary precedent lane exists, but split analog lanes remain active.")
        elif label == "conflicting_precedent":
            lines.append("Competing analog lanes conflict; no single precedent lane should be treated as coherent.")
        elif label == "ambiguous_precedent":
            lines.append("Precedent lanes are sparse or mixed; coherence cannot be established yet.")

        return {
            "precedent_agreement_label": label,
            "precedent_agreement_score": score,
            "split_precedent_active": label in {"partially_split_precedent", "conflicting_precedent"},
            "basis": {
                "analog_agreement_label": agreement_label,
                "cluster_size": cluster_size,
                "divergence_signal_count": divergence_count,
                "separation_signal_count": separation_count,
                "family_review_label": family_review_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _precedent_readiness_state(
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        scenario_family_fit_state: dict,
        analog_confidence_state: dict,
        precedent_quality_state: dict,
        precedent_agreement_state: dict,
    ) -> dict:
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        novelty_score = float(scenario_novelty_state.get("novelty_score", 0.0))
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        fit_label = scenario_family_fit_state.get("fit_label", "weak_family_fit")
        analog_confidence_label = analog_confidence_state.get("analog_confidence_label", "weak_analog_confidence")
        quality_label = precedent_quality_state.get("precedent_quality_label", "no_useful_precedent")
        quality_score = float(precedent_quality_state.get("precedent_quality_score", 0.0))
        agreement_label = precedent_agreement_state.get("precedent_agreement_label", "ambiguous_precedent")
        agreement_score = float(precedent_agreement_state.get("precedent_agreement_score", 0.0))

        score = min(1.0, (quality_score * 0.56) + (agreement_score * 0.24) + (0.2 if fit_label == "strong_family_fit" else 0.1 if fit_label == "moderate_family_fit" else 0.0))
        score -= 0.22 if novelty_label == "high_novelty" or novelty_score >= 0.66 else 0.0
        score -= 0.12 if hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"} else 0.0
        score -= 0.1 if analog_confidence_label in {"weak_analog_confidence", "novelty_limited_analog_confidence"} else 0.0
        score = round(max(0.0, min(1.0, score)), 3)

        if novelty_label == "high_novelty" and score < 0.7:
            label = "novelty_limited_precedent_context"
        elif quality_label == "strong_precedent" and agreement_label == "coherent_precedent" and score >= 0.64:
            label = "strong_precedent_context"
        elif quality_label in {"strong_precedent", "moderate_precedent"} and agreement_label in {"coherent_precedent", "partially_split_precedent"} and score >= 0.44:
            label = "moderate_precedent_context"
        else:
            label = "weak_background_context"

        lines = [f"Precedent readiness: {label} ({score:.2f})."]
        if label == "weak_background_context":
            lines.append("Historical analogs remain background context, not strong guidance.")
        elif label == "novelty_limited_precedent_context":
            lines.append("Historical precedent exists, but novelty limits direct reuse.")

        return {
            "precedent_readiness_label": label,
            "precedent_readiness_score": score,
            "basis": {
                "precedent_quality_label": quality_label,
                "precedent_agreement_label": agreement_label,
                "scenario_novelty_label": novelty_label,
                "hybrid_family_label": hybrid_label,
                "family_fit_label": fit_label,
                "analog_confidence_label": analog_confidence_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _review_readiness_state(
        precedent_quality_state: dict,
        precedent_agreement_state: dict,
        precedent_readiness_state: dict,
        scenario_family_fit_state: dict,
        scenario_novelty_state: dict,
        analog_cluster_state: dict,
    ) -> dict:
        quality_score = float(precedent_quality_state.get("precedent_quality_score", 0.0))
        agreement_score = float(precedent_agreement_state.get("precedent_agreement_score", 0.0))
        readiness_score = float(precedent_readiness_state.get("precedent_readiness_score", 0.0))
        fit_score = float(scenario_family_fit_state.get("fit_score", 0.0))
        novelty_score = float(scenario_novelty_state.get("novelty_score", 0.0))
        cluster_size = int(analog_cluster_state.get("cluster_size", 0))
        agreement_label = precedent_agreement_state.get("precedent_agreement_label", "ambiguous_precedent")

        score = round(
            max(
                0.0,
                min(
                    1.0,
                    (quality_score * 0.34)
                    + (agreement_score * 0.2)
                    + (readiness_score * 0.32)
                    + (fit_score * 0.14)
                    - (0.18 if novelty_score >= 0.66 else 0.0),
                ),
            ),
            3,
        )
        if agreement_label == "conflicting_precedent":
            label = "exception_heavy_review_readiness"
        elif score >= 0.7 and cluster_size >= 2:
            label = "high_review_readiness"
        elif score >= 0.44:
            label = "moderate_review_readiness"
        else:
            label = "low_review_readiness"
        return {
            "review_readiness_label": label,
            "review_readiness_score": score,
            "compact_lines": [f"Review readiness: {label} ({score:.2f})."][:2],
            "basis": {
                "precedent_quality_label": precedent_quality_state.get("precedent_quality_label", "no_useful_precedent"),
                "precedent_agreement_label": agreement_label,
                "precedent_readiness_label": precedent_readiness_state.get("precedent_readiness_label", "weak_background_context"),
                "family_fit_label": scenario_family_fit_state.get("fit_label", "weak_family_fit"),
                "novelty_label": scenario_novelty_state.get("novelty_label", "moderate_novelty"),
                "cluster_size": cluster_size,
            },
        }

    @staticmethod
    def _exception_review_state(
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        analog_agreement_state: dict,
        precedent_agreement_state: dict,
        divergence_review_state: dict,
    ) -> dict:
        novelty_active = scenario_novelty_state.get("novelty_label") == "high_novelty" or float(scenario_novelty_state.get("novelty_score", 0.0)) >= 0.66
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        hybrid_active = hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        split_active = precedent_agreement_state.get("precedent_agreement_label") in {"partially_split_precedent", "conflicting_precedent"}
        conflict_active = analog_agreement_state.get("agreement_label") == "analog_conflict" or len(divergence_review_state.get("archetype_divergence_signals") or []) >= 2
        if conflict_active:
            label = "conflicting_analog_exception_case"
        elif split_active:
            label = "split_precedent_exception_case"
        elif novelty_active:
            label = "novelty_driven_exception_case"
        elif hybrid_active:
            label = "hybrid_driven_exception_case"
        else:
            label = "precedent_friendly_case"
        return {
            "exception_review_label": label,
            "novelty_driven_exception_case": novelty_active,
            "hybrid_driven_exception_case": hybrid_active,
            "split_precedent_exception_case": split_active,
            "conflicting_analog_exception_case": conflict_active,
            "compact_lines": [f"Exception handling: {label}."][:2],
            "basis": {
                "novelty_label": scenario_novelty_state.get("novelty_label", "moderate_novelty"),
                "hybrid_label": hybrid_label,
                "analog_agreement_label": analog_agreement_state.get("agreement_label", "analog_ambiguity"),
                "precedent_agreement_label": precedent_agreement_state.get("precedent_agreement_label", "ambiguous_precedent"),
            },
        }

    @staticmethod
    def _precedent_downgrade_state(
        evidence_confidence_state: dict,
        precedent_quality_state: dict,
        precedent_agreement_state: dict,
        precedent_readiness_state: dict,
        analog_mismatch_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        exception_review_state: dict,
    ) -> dict:
        reuse_state = (evidence_confidence_state.get("historical_evidence_reuse_state") or {})
        novelty_limited = bool(reuse_state.get("novelty_limited")) or bool(analog_mismatch_state.get("novelty_limited_analog"))
        split_lanes = precedent_agreement_state.get("precedent_agreement_label") in {"partially_split_precedent", "conflicting_precedent"} or bool(exception_review_state.get("split_precedent_exception_case"))
        conflict_limited = bool(analog_mismatch_state.get("conflicting_analog_evidence")) or bool(exception_review_state.get("conflicting_analog_exception_case"))
        weak_background = precedent_readiness_state.get("precedent_readiness_label") == "weak_background_context" or precedent_quality_state.get("precedent_quality_label") in {"weak_precedent", "no_useful_precedent"}
        if conflict_limited:
            label = "precedent_exists_but_conflict_weakens_reuse"
        elif split_lanes:
            label = "precedent_exists_but_split_lanes_weaken_reuse"
        elif novelty_limited or scenario_novelty_state.get("novelty_label") == "high_novelty" or hybrid_family_state.get("hybrid_label") in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}:
            label = "precedent_exists_but_novelty_limits_reuse"
        elif weak_background:
            label = "precedent_exists_as_weak_background_context"
        else:
            label = "no_material_downgrade_needed"
        return {
            "downgrade_label": label,
            "precedent_exists_but_novelty_limits_reuse": label == "precedent_exists_but_novelty_limits_reuse",
            "precedent_exists_but_split_lanes_weaken_reuse": label == "precedent_exists_but_split_lanes_weaken_reuse",
            "precedent_exists_but_conflict_weakens_reuse": label == "precedent_exists_but_conflict_weakens_reuse",
            "precedent_exists_as_weak_background_context": label == "precedent_exists_as_weak_background_context",
            "compact_lines": [f"Precedent downgrade path: {label}."][:2],
            "basis": {"reuse_label": reuse_state.get("reuse_label", "low_reuse_historical_context")},
        }

    @staticmethod
    def _operator_review_stance_evidence(
        review_readiness_state: dict,
        exception_review_state: dict,
        precedent_downgrade_state: dict,
        precedent_readiness_state: dict,
    ) -> dict:
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        downgrade_label = precedent_downgrade_state.get("downgrade_label", "precedent_exists_as_weak_background_context")
        if exception_label != "precedent_friendly_case":
            stance_label = "exception_heavy_review_stance"
        elif readiness_label == "high_review_readiness" and downgrade_label == "no_material_downgrade_needed":
            stance_label = "strong_precedent_backed_review_stance"
        elif readiness_label in {"high_review_readiness", "moderate_review_readiness"}:
            stance_label = "moderate_precedent_backed_review_stance"
        elif precedent_readiness_state.get("precedent_readiness_label") == "weak_background_context":
            stance_label = "weak_background_review_stance"
        else:
            stance_label = "moderate_precedent_backed_review_stance"
        lines = [
            f"Operator review stance: {stance_label}.",
            f"Readiness={readiness_label}; exception={exception_label}; downgrade={downgrade_label}.",
        ]
        return {
            "review_stance_label": stance_label,
            "review_stance_lines": lines[:2],
            "compact_lines": lines[:2],
        }

    @staticmethod
    def _audit_basis_state(
        review_readiness_state: dict,
        exception_review_state: dict,
        precedent_downgrade_state: dict,
        precedent_readiness_state: dict,
        precedent_quality_state: dict,
        analog_confidence_state: dict,
        scenario_family_fit_state: dict,
        divergence_review_state: dict,
        family_level_intervention_review: dict,
    ) -> dict:
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        downgrade_label = precedent_downgrade_state.get("downgrade_label", "precedent_exists_as_weak_background_context")
        precedent_quality_label = precedent_quality_state.get("precedent_quality_label", "no_useful_precedent")
        confidence_label = analog_confidence_state.get("analog_confidence_label", "weak_analog_confidence")
        fit_label = scenario_family_fit_state.get("fit_label", "weak_family_fit")
        divergence_active = bool((divergence_review_state.get("archetype_divergence_signals") or [])[:1])
        intervention_review_label = family_level_intervention_review.get("summary_label", "mixed_family_traction")

        if exception_label != "precedent_friendly_case" or readiness_label == "exception_heavy_review_readiness":
            basis_label = "exception_heavy_audit_basis"
        elif readiness_label == "high_review_readiness" and downgrade_label == "no_material_downgrade_needed" and precedent_quality_label == "strong_precedent":
            basis_label = "strong_precedent_backed_audit_basis"
        elif readiness_label in {"high_review_readiness", "moderate_review_readiness"} and confidence_label != "weak_analog_confidence" and fit_label != "weak_family_fit":
            basis_label = "mixed_usable_audit_basis"
        else:
            basis_label = "weak_background_audit_basis"

        lines = [
            f"Audit basis: {basis_label}.",
            f"Readiness={readiness_label}; downgrade={downgrade_label}; exception={exception_label}.",
            f"Bounded match context: quality={precedent_quality_label}; analog confidence={confidence_label}; family fit={fit_label}.",
        ]
        if divergence_active:
            lines.append("Divergence signals remain active in the current bounded scenario comparison.")
        if intervention_review_label != "mixed_family_traction":
            lines.append(f"Intervention-review context: {intervention_review_label}.")

        return {
            "audit_basis_label": basis_label,
            "strong_precedent_backed_audit_basis": basis_label == "strong_precedent_backed_audit_basis",
            "mixed_usable_audit_basis": basis_label == "mixed_usable_audit_basis",
            "weak_background_audit_basis": basis_label == "weak_background_audit_basis",
            "exception_heavy_audit_basis": basis_label == "exception_heavy_audit_basis",
            "basis": {
                "review_readiness_label": readiness_label,
                "exception_review_label": exception_label,
                "precedent_downgrade_label": downgrade_label,
                "precedent_readiness_label": precedent_readiness_state.get("precedent_readiness_label", "weak_background_context"),
                "precedent_quality_label": precedent_quality_label,
                "analog_confidence_label": confidence_label,
                "family_fit_label": fit_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _evidence_lane_state(
        precedent_quality_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        analog_cluster_state: dict,
        analog_agreement_state: dict,
        divergence_review_state: dict,
        family_level_intervention_review: dict,
        review_readiness_state: dict,
    ) -> dict:
        quality_label = precedent_quality_state.get("precedent_quality_label", "no_useful_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        agreement_label = analog_agreement_state.get("agreement_label", "analog_ambiguity")
        cluster_size = int(analog_cluster_state.get("cluster_size", 0))
        divergence_count = len(divergence_review_state.get("archetype_divergence_signals") or [])
        intervention_label = family_level_intervention_review.get("summary_label", "mixed_family_traction")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")

        if agreement_label == "analog_conflict" or divergence_count >= 2:
            lane_label = "conflicting_evidence_lanes"
        elif cluster_size <= 1 and quality_label in {"weak_precedent", "no_useful_precedent"}:
            lane_label = "sparse_ambiguous_evidence_lanes"
        elif novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}:
            lane_label = "partially_reinforcing_evidence_lanes"
        elif readiness_label in {"high_review_readiness", "moderate_review_readiness"} and agreement_label in {"analog_alignment", "analog_broad_alignment"}:
            lane_label = "reinforcing_evidence_lanes"
        else:
            lane_label = "partially_reinforcing_evidence_lanes"

        lines = [
            f"Evidence lanes: {lane_label}.",
            f"Precedent={quality_label}; analog agreement={agreement_label}; novelty={novelty_label}; hybrid={hybrid_label}.",
        ]
        if intervention_label != "mixed_family_traction":
            lines.append(f"Intervention review lane: {intervention_label}.")
        if divergence_count:
            lines.append(f"Divergence lane count: {divergence_count}.")

        return {
            "evidence_lane_label": lane_label,
            "reinforcing_evidence_lanes": lane_label == "reinforcing_evidence_lanes",
            "partially_reinforcing_evidence_lanes": lane_label == "partially_reinforcing_evidence_lanes",
            "conflicting_evidence_lanes": lane_label == "conflicting_evidence_lanes",
            "sparse_ambiguous_evidence_lanes": lane_label == "sparse_ambiguous_evidence_lanes",
            "basis": {
                "precedent_quality_label": quality_label,
                "analog_agreement_label": agreement_label,
                "cluster_size": cluster_size,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "intervention_review_label": intervention_label,
                "review_readiness_label": readiness_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _underdetermined_review_state(
        review_readiness_state: dict,
        exception_review_state: dict,
        precedent_downgrade_state: dict,
        evidence_confidence_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
        precedent_quality_state: dict,
    ) -> dict:
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        downgrade_label = precedent_downgrade_state.get("downgrade_label", "precedent_exists_as_weak_background_context")
        confidence_label = evidence_confidence_state.get("confidence_label", "low_confidence_context")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        quality_label = precedent_quality_state.get("precedent_quality_label", "no_useful_precedent")

        if lane_label == "conflicting_evidence_lanes" or exception_label == "conflicting_analog_exception_case":
            label = "underdetermined_due_to_split_conflict"
        elif novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}:
            label = "underdetermined_due_to_novelty"
        elif quality_label in {"weak_precedent", "no_useful_precedent"} or downgrade_label == "precedent_exists_as_weak_background_context":
            label = "underdetermined_due_to_sparse_precedent"
        elif readiness_label in {"high_review_readiness", "moderate_review_readiness"} and confidence_label in {"high_confidence_context", "moderate_confidence_context"} and lane_label in {"reinforcing_evidence_lanes", "partially_reinforcing_evidence_lanes"}:
            label = "sufficiently_determined_review"
        else:
            label = "underdetermined_due_to_sparse_precedent"

        lines = [
            f"Review determinacy: {label}.",
            f"Lane state={lane_label}; confidence={confidence_label}; readiness={readiness_label}.",
        ]

        return {
            "underdetermined_review_label": label,
            "underdetermined_due_to_novelty": label == "underdetermined_due_to_novelty",
            "underdetermined_due_to_split_conflict": label == "underdetermined_due_to_split_conflict",
            "underdetermined_due_to_sparse_precedent": label == "underdetermined_due_to_sparse_precedent",
            "sufficiently_determined_review": label == "sufficiently_determined_review",
            "basis": {
                "review_readiness_label": readiness_label,
                "exception_review_label": exception_label,
                "precedent_downgrade_label": downgrade_label,
                "confidence_label": confidence_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
                "precedent_quality_label": quality_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_audit_basis_evidence(
        audit_basis_state: dict,
        evidence_lane_state: dict,
        underdetermined_review_state: dict,
        operator_precedent_evidence: dict,
        review_readiness_state: dict,
        exception_review_state: dict,
        precedent_downgrade_state: dict,
    ) -> dict:
        strongest_basis = audit_basis_state.get("audit_basis_label", "weak_background_audit_basis")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        underdetermined_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        match_axes = (operator_precedent_evidence.get("precedent_main_match_axes") or operator_precedent_evidence.get("cluster_main_match_axes") or [])[:3]
        lines = [
            f"Strongest audit basis: {strongest_basis}.",
            f"Evidence lanes: {lane_label}.",
            f"Determination qualifier: {underdetermined_label}.",
        ]
        if match_axes:
            lines.append(f"Audit basis mainly matched on: {', '.join(match_axes)}.")
        lines.append(
            f"Review stance context: {review_readiness_state.get('review_readiness_label', 'low_review_readiness')} / {exception_review_state.get('exception_review_label', 'precedent_friendly_case')} / {precedent_downgrade_state.get('downgrade_label', 'precedent_exists_as_weak_background_context')}."
        )
        return {
            "strongest_audit_basis": strongest_basis,
            "evidence_lane_label": lane_label,
            "underdetermined_review_label": underdetermined_label,
            "audit_basis_match_axes": match_axes,
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _review_conclusion_state(
        review_synthesis_state: dict,
        synthesis_contestation_state: dict,
        synthesis_downweight_state: dict,
        operator_review_synthesis_evidence: dict,
        audit_basis_state: dict,
        review_stance_state: dict,
    ) -> dict:
        synthesis_label = review_synthesis_state.get("review_synthesis_label", "weak_background_review_synthesis")
        contest_label = synthesis_contestation_state.get("synthesis_contestation_label", "partially_contested_synthesis")
        downweight_label = synthesis_downweight_state.get("synthesis_downweight_label", "light_downweight_cautionary")
        audit_label = audit_basis_state.get("audit_basis_label", "weak_background_audit_basis")
        stance_label = review_stance_state.get("review_readiness_label", "low_review_readiness")

        if synthesis_label == "exception_heavy_review_synthesis" or downweight_label == "strong_downweight_exception_heavy":
            label = "exception_heavy_conclusion"
        elif synthesis_label == "strong_coherent_review_synthesis" and contest_label == "coherent_synthesis" and downweight_label == "minimal_downweight_preserve_strength":
            label = "strong_supported_conclusion"
        elif synthesis_label in {"strong_coherent_review_synthesis", "moderate_usable_review_synthesis"} and contest_label in {"coherent_synthesis", "partially_contested_synthesis"}:
            label = "moderate_usable_conclusion"
        else:
            label = "weak_background_conclusion"

        lines = [
            f"Review conclusion: {label}.",
            f"Synthesis={synthesis_label}; contestation={contest_label}; downweight={downweight_label}.",
            f"Audit basis={audit_label}; review stance={stance_label}.",
        ]
        for line in (operator_review_synthesis_evidence.get("compact_lines") or [])[:1]:
            lines.append(f"Synthesis evidence: {line}")

        return {
            "review_conclusion_label": label,
            "strong_supported_conclusion": label == "strong_supported_conclusion",
            "moderate_usable_conclusion": label == "moderate_usable_conclusion",
            "weak_background_conclusion": label == "weak_background_conclusion",
            "exception_heavy_conclusion": label == "exception_heavy_conclusion",
            "basis": {
                "review_synthesis_label": synthesis_label,
                "synthesis_contestation_label": contest_label,
                "synthesis_downweight_label": downweight_label,
                "audit_basis_label": audit_label,
                "review_stance_label": stance_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _review_takeaway_caveat_state(
        review_conclusion_state: dict,
        review_synthesis_state: dict,
        synthesis_contestation_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        precedent_downgrade_state: dict,
        divergence_review_state: dict,
        intervention_review_state: dict,
        operator_review_synthesis_evidence: dict,
    ) -> dict:
        conclusion_label = review_conclusion_state.get("review_conclusion_label", "weak_background_conclusion")
        synthesis_label = review_synthesis_state.get("review_synthesis_label", "weak_background_review_synthesis")
        contest_label = synthesis_contestation_state.get("synthesis_contestation_label", "partially_contested_synthesis")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        downgrade_label = precedent_downgrade_state.get("downgrade_label", "precedent_exists_as_weak_background_context")
        intervention_label = intervention_review_state.get("summary_label", "mixed_family_traction")
        divergence_count = len((divergence_review_state.get("archetype_divergence_signals") or [])[:4])
        axes = (operator_review_synthesis_evidence.get("main_evidence_axes") or [])[:3]
        evidence_axis = axes[0] if axes else "no_clear_axis"

        strongest_takeaway = {
            "strong_supported_conclusion": "Coherent synthesis points to a strong supported bottom-line signal.",
            "moderate_usable_conclusion": "Synthesis indicates a usable bottom-line signal with bounded confidence.",
            "weak_background_conclusion": "Synthesis provides only a weak background signal for the bottom line.",
            "exception_heavy_conclusion": "Synthesis shows exception-heavy patterns that dominate the bottom line.",
        }.get(conclusion_label, "Synthesis does not yet provide a stable bottom-line signal.")

        if contest_label in {"contested_synthesis", "sparse_underdetermined_synthesis"}:
            primary_caveat = "Evidence remains contested or sparse enough that the conclusion should be softened."
        elif under_label != "sufficiently_determined_review":
            primary_caveat = "Review remains underdetermined, so the takeaway should be treated as provisional."
        elif novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}:
            primary_caveat = "Novelty/hybrid family structure limits direct carry-over confidence."
        elif divergence_count >= 2 or intervention_label == "same_family_repeated_weak_traction":
            primary_caveat = "Divergence/intervention history weakens direct confidence in the main takeaway."
        elif downgrade_label != "precedent_upgrade_not_required":
            primary_caveat = "Precedent downgrade signals require caution around conclusion strength."
        else:
            primary_caveat = "No dominant caveat beyond routine uncertainty."

        caution_qualifier = {
            "coherent_synthesis": "low_caution_coherent",
            "partially_contested_synthesis": "moderate_caution_partial_contestation",
            "contested_synthesis": "high_caution_contested",
            "sparse_underdetermined_synthesis": "high_caution_sparse_underdetermined",
        }.get(contest_label, "moderate_caution_partial_contestation")

        lines = [
            f"Strongest takeaway: {strongest_takeaway}",
            f"Primary caveat: {primary_caveat}",
            f"Evidence axis: {evidence_axis}; caution={caution_qualifier}.",
        ]

        return {
            "strongest_takeaway": strongest_takeaway,
            "primary_caveat": primary_caveat,
            "supporting_evidence_axis": evidence_axis,
            "caution_qualifier": caution_qualifier,
            "basis": {
                "review_conclusion_label": conclusion_label,
                "review_synthesis_label": synthesis_label,
                "synthesis_contestation_label": contest_label,
                "underdetermined_review_label": under_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "precedent_downgrade_label": downgrade_label,
                "divergence_count": divergence_count,
                "intervention_review_label": intervention_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _cautious_conclusion_state(
        review_conclusion_state: dict,
        review_takeaway_caveat_state: dict,
        synthesis_downweight_state: dict,
        underdetermined_review_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_confidence_state: dict,
        synthesis_contestation_state: dict,
    ) -> dict:
        conclusion_label = review_conclusion_state.get("review_conclusion_label", "weak_background_conclusion")
        caveat = review_takeaway_caveat_state.get("primary_caveat", "No dominant caveat beyond routine uncertainty.")
        downweight_label = synthesis_downweight_state.get("synthesis_downweight_label", "light_downweight_cautionary")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        confidence_label = evidence_confidence_state.get("confidence_label", "low_confidence_context")
        contest_label = synthesis_contestation_state.get("synthesis_contestation_label", "partially_contested_synthesis")

        if downweight_label == "minimal_downweight_preserve_strength" and contest_label == "coherent_synthesis" and under_label == "sufficiently_determined_review":
            qualification = "preserve_strength_with_routine_caution"
        elif downweight_label == "strong_downweight_exception_heavy" or exception_label != "precedent_friendly_case":
            qualification = "exception_heavy_limit_certainty"
        elif downweight_label == "moderate_downweight_underdetermined" or under_label != "sufficiently_determined_review":
            qualification = "soften_for_contested_or_underdetermined_evidence"
        else:
            qualification = "light_caution_qualification"

        lines = [
            f"Cautious conclusion qualification: {qualification}.",
            f"Conclusion={conclusion_label}; contestation={contest_label}; downweight={downweight_label}.",
            f"Caveat={caveat}",
            f"Confidence={confidence_label}; novelty={novelty_label}; hybrid={hybrid_label}.",
        ]
        return {
            "conclusion_qualification_label": qualification,
            "bottom_line_confidence_band": {
                "preserve_strength_with_routine_caution": "higher_confidence_band",
                "light_caution_qualification": "moderate_confidence_band",
                "soften_for_contested_or_underdetermined_evidence": "qualified_low_to_moderate_confidence_band",
                "exception_heavy_limit_certainty": "limited_certainty_band",
            }.get(qualification, "qualified_low_to_moderate_confidence_band"),
            "basis": {
                "review_conclusion_label": conclusion_label,
                "synthesis_downweight_label": downweight_label,
                "underdetermined_review_label": under_label,
                "exception_review_label": exception_label,
                "confidence_label": confidence_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "synthesis_contestation_label": contest_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _operator_conclusion_evidence(
        review_conclusion_state: dict,
        review_takeaway_caveat_state: dict,
        cautious_conclusion_state: dict,
        operator_review_synthesis_evidence: dict,
        compact_historical_synthesis_lines: list[str],
    ) -> dict:
        bottom_line = review_conclusion_state.get("review_conclusion_label", "weak_background_conclusion")
        takeaway = review_takeaway_caveat_state.get("strongest_takeaway", "No stable takeaway available yet.")
        caveat = review_takeaway_caveat_state.get("primary_caveat", "No dominant caveat beyond routine uncertainty.")
        caution = cautious_conclusion_state.get("conclusion_qualification_label", "soften_for_contested_or_underdetermined_evidence")
        confidence_band = cautious_conclusion_state.get("bottom_line_confidence_band", "qualified_low_to_moderate_confidence_band")
        evidence_axis = review_takeaway_caveat_state.get("supporting_evidence_axis", "no_clear_axis")
        lines = [
            f"Bottom line: {bottom_line}.",
            f"Takeaway: {takeaway}",
            f"Caveat: {caveat}",
            f"Qualifier: {caution} ({confidence_band}; axis={evidence_axis}).",
        ]
        for line in (operator_review_synthesis_evidence.get("compact_lines") or [])[:1]:
            lines.append(f"Evidence: {line}")
        for line in (compact_historical_synthesis_lines or [])[:1]:
            lines.append(f"History: {line}")
        return {
            "bottom_line_conclusion": bottom_line,
            "strongest_takeaway": takeaway,
            "main_caveat": caveat,
            "confidence_caution_qualifier": caution,
            "confidence_band": confidence_band,
            "supporting_evidence_axis": evidence_axis,
            "compact_lines": lines[:5],
        }

    @staticmethod
    def _review_verdict_state(
        review_conclusion_state: dict,
        review_takeaway_caveat_state: dict,
        cautious_conclusion_state: dict,
        operator_conclusion_evidence: dict,
        review_synthesis_state: dict,
        review_readiness_state: dict,
    ) -> dict:
        conclusion_label = review_conclusion_state.get("review_conclusion_label", "weak_background_conclusion")
        synthesis_label = review_synthesis_state.get("review_synthesis_label", "weak_background_review_synthesis")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        caveat_qualifier = review_takeaway_caveat_state.get("caution_qualifier", "moderate_caution_partial_contestation")
        confidence_band = cautious_conclusion_state.get("bottom_line_confidence_band", "qualified_low_to_moderate_confidence_band")
        qualification_label = cautious_conclusion_state.get("conclusion_qualification_label", "soften_for_contested_or_underdetermined_evidence")
        supporting_axis = operator_conclusion_evidence.get("supporting_evidence_axis", "no_clear_axis")

        if conclusion_label == "exception_heavy_conclusion":
            verdict_label = "exception_heavy_verdict"
        elif conclusion_label == "strong_supported_conclusion" and confidence_band == "higher_confidence_band":
            verdict_label = "strong_supported_verdict"
        elif conclusion_label in {"strong_supported_conclusion", "moderate_usable_conclusion"} and confidence_band in {
            "moderate_confidence_band",
            "higher_confidence_band",
        }:
            verdict_label = "moderate_usable_verdict"
        elif conclusion_label == "weak_background_conclusion" or confidence_band in {
            "qualified_low_to_moderate_confidence_band",
            "limited_certainty_band",
        }:
            verdict_label = "provisional_verdict"
        else:
            verdict_label = "moderate_usable_verdict"

        lines = [
            f"Overall review verdict: {verdict_label}.",
            f"Conclusion={conclusion_label}; synthesis={synthesis_label}; readiness={readiness_label}.",
            f"Caution={caveat_qualifier}; confidence_band={confidence_band}; qualification={qualification_label}; axis={supporting_axis}.",
        ]
        return {
            "review_verdict_label": verdict_label,
            "strong_supported_verdict": verdict_label == "strong_supported_verdict",
            "moderate_usable_verdict": verdict_label == "moderate_usable_verdict",
            "provisional_verdict": verdict_label == "provisional_verdict",
            "exception_heavy_verdict": verdict_label == "exception_heavy_verdict",
            "basis": {
                "review_conclusion_label": conclusion_label,
                "review_synthesis_label": synthesis_label,
                "review_readiness_label": readiness_label,
                "caution_qualifier": caveat_qualifier,
                "bottom_line_confidence_band": confidence_band,
                "conclusion_qualification_label": qualification_label,
                "supporting_evidence_axis": supporting_axis,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _verdict_stability_state(
        review_verdict_state: dict,
        synthesis_contestation_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_confidence_state: dict,
        precedent_downgrade_state: dict,
        cautious_conclusion_state: dict,
    ) -> dict:
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        contest_label = synthesis_contestation_state.get("synthesis_contestation_label", "partially_contested_synthesis")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        confidence_label = evidence_confidence_state.get("confidence_label", "low_confidence_context")
        downgrade_label = precedent_downgrade_state.get("downgrade_label", "precedent_exists_as_weak_background_context")
        qualification_label = cautious_conclusion_state.get("conclusion_qualification_label", "soften_for_contested_or_underdetermined_evidence")

        highly_provisional_trigger = (
            contest_label in {"contested_synthesis", "sparse_underdetermined_synthesis"}
            or under_label in {"underdetermined_due_to_split_conflict", "underdetermined_due_to_novelty"}
            or confidence_label == "low_confidence_context"
        )
        provisional_trigger = (
            under_label != "sufficiently_determined_review"
            or novelty_label == "high_novelty"
            or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
            or downgrade_label == "precedent_exists_as_weak_background_context"
        )

        if verdict_label == "strong_supported_verdict" and not highly_provisional_trigger and not provisional_trigger:
            stability_label = "stable_verdict"
        elif verdict_label in {"strong_supported_verdict", "moderate_usable_verdict"} and not highly_provisional_trigger:
            stability_label = "mostly_stable_verdict"
        elif highly_provisional_trigger or verdict_label in {"provisional_verdict", "exception_heavy_verdict"}:
            stability_label = "highly_provisional_verdict" if highly_provisional_trigger else "provisional_verdict"
        else:
            stability_label = "provisional_verdict"

        lines = [
            f"Verdict stability: {stability_label}.",
            f"Contestation={contest_label}; underdetermined={under_label}; confidence={confidence_label}.",
            f"Novelty={novelty_label}; hybrid={hybrid_label}; downgrade={downgrade_label}; qualification={qualification_label}.",
        ]
        return {
            "verdict_stability_label": stability_label,
            "stable_verdict": stability_label == "stable_verdict",
            "mostly_stable_verdict": stability_label == "mostly_stable_verdict",
            "provisional_verdict": stability_label == "provisional_verdict",
            "highly_provisional_verdict": stability_label == "highly_provisional_verdict",
            "basis": {
                "review_verdict_label": verdict_label,
                "synthesis_contestation_label": contest_label,
                "underdetermined_review_label": under_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "confidence_label": confidence_label,
                "precedent_downgrade_label": downgrade_label,
                "cautious_conclusion_label": qualification_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _verdict_caveat_override_state(
        review_takeaway_caveat_state: dict,
        cautious_conclusion_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        synthesis_contestation_state: dict,
        evidence_lane_state: dict,
        review_verdict_state: dict,
    ) -> dict:
        caveat_text = review_takeaway_caveat_state.get("primary_caveat", "No dominant caveat beyond routine uncertainty.")
        caution_qualifier = review_takeaway_caveat_state.get("caution_qualifier", "moderate_caution_partial_contestation")
        qualification_label = cautious_conclusion_state.get("conclusion_qualification_label", "soften_for_contested_or_underdetermined_evidence")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        contest_label = synthesis_contestation_state.get("synthesis_contestation_label", "partially_contested_synthesis")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")

        if exception_label != "precedent_friendly_case" or qualification_label == "exception_heavy_limit_certainty":
            override_label = "exception_overridden_verdict"
        elif caution_qualifier in {"high_caution_contested", "high_caution_sparse_underdetermined"} or contest_label in {
            "contested_synthesis",
            "sparse_underdetermined_synthesis",
        }:
            override_label = "caveat_limited_verdict"
        elif novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"} or lane_label == "conflicting_evidence_lanes":
            override_label = "caveat_balanced_verdict"
        else:
            override_label = "caveat_light_verdict"

        lines = [
            f"Caveat-pressure override: {override_label}.",
            f"Verdict={verdict_label}; caveat={caution_qualifier}; qualification={qualification_label}; contestation={contest_label}.",
            f"Exception={exception_label}; novelty={novelty_label}; hybrid={hybrid_label}; lane={lane_label}.",
            f"Primary caveat pressure: {caveat_text}",
        ]
        return {
            "verdict_caveat_override_label": override_label,
            "caveat_limited_verdict": override_label == "caveat_limited_verdict",
            "caveat_balanced_verdict": override_label == "caveat_balanced_verdict",
            "caveat_light_verdict": override_label == "caveat_light_verdict",
            "exception_overridden_verdict": override_label == "exception_overridden_verdict",
            "basis": {
                "review_verdict_label": verdict_label,
                "caution_qualifier": caution_qualifier,
                "conclusion_qualification_label": qualification_label,
                "exception_review_label": exception_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "synthesis_contestation_label": contest_label,
                "evidence_lane_label": lane_label,
            },
            "primary_caveat": caveat_text,
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _operator_verdict_evidence(
        review_verdict_state: dict,
        verdict_stability_state: dict,
        verdict_caveat_override_state: dict,
        operator_conclusion_evidence: dict,
        operator_review_synthesis_evidence: dict,
    ) -> dict:
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        caveat_label = verdict_caveat_override_state.get("verdict_caveat_override_label", "caveat_balanced_verdict")
        main_caveat = verdict_caveat_override_state.get("primary_caveat") or operator_conclusion_evidence.get("main_caveat")
        supporting_axis = operator_conclusion_evidence.get("supporting_evidence_axis", "no_clear_axis")
        synthesis_axis = ((operator_review_synthesis_evidence.get("main_evidence_axes") or [])[:1] or [supporting_axis])[0]
        lines = [
            f"Overall verdict: {verdict_label}.",
            f"Stability qualifier: {stability_label}.",
            f"Caveat-pressure qualifier: {caveat_label}.",
            f"Main support axis: {synthesis_axis}; caveat: {main_caveat or 'no dominant caveat'}",
        ]
        return {
            "overall_verdict": verdict_label,
            "stability_qualifier": stability_label,
            "main_caveat_pressure": caveat_label,
            "main_supporting_axis": synthesis_axis,
            "main_caveat": main_caveat,
            "compact_lines": lines[:4],
        }


    @staticmethod
    def _review_disposition_state(
        review_verdict_state: dict,
        verdict_stability_state: dict,
        verdict_caveat_override_state: dict,
        operator_verdict_evidence: dict,
        review_conclusion_state: dict,
        review_readiness_state: dict,
    ) -> dict:
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        caveat_label = verdict_caveat_override_state.get("verdict_caveat_override_label", "caveat_balanced_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        conclusion_label = review_conclusion_state.get("review_conclusion_label", "weak_background_conclusion")
        support_axis = operator_verdict_evidence.get("main_supporting_axis", "no_clear_axis")

        unresolved = stability_label in {"provisional_verdict", "highly_provisional_verdict"}
        open_question = (
            verdict_label in {"provisional_verdict", "exception_heavy_verdict"}
            and caveat_label in {"caveat_balanced_verdict", "exception_overridden_verdict"}
            and not unresolved
        )
        guarded = (
            verdict_label in {"moderate_usable_verdict", "strong_supported_verdict"}
            and caveat_label in {"caveat_limited_verdict", "caveat_balanced_verdict"}
            and stability_label == "mostly_stable_verdict"
        )
        strong_supported = (
            verdict_label == "strong_supported_verdict"
            and stability_label == "stable_verdict"
            and caveat_label == "caveat_light_verdict"
            and readiness_label in {"high_review_readiness", "moderate_review_readiness"}
        )

        if strong_supported:
            label = "strong_supported_disposition"
            qualifier = "strong"
        elif guarded:
            label = "guarded_disposition"
            qualifier = "guarded"
        elif unresolved:
            label = "unresolved_disposition"
            qualifier = "unresolved"
        elif open_question:
            label = "open_question_disposition"
            qualifier = "open_question"
        else:
            label = "guarded_disposition" if verdict_label == "moderate_usable_verdict" else "open_question_disposition"
            qualifier = "guarded" if label == "guarded_disposition" else "open_question"

        lines = [
            f"Overall review disposition: {label}.",
            f"Qualifier={qualifier}; verdict={verdict_label}; stability={stability_label}; caveat={caveat_label}.",
            f"Readiness={readiness_label}; conclusion={conclusion_label}; support_axis={support_axis}.",
        ]
        return {
            "review_disposition_label": label,
            "disposition_qualifier": qualifier,
            "strong_supported_disposition": label == "strong_supported_disposition",
            "guarded_disposition": label == "guarded_disposition",
            "open_question_disposition": label == "open_question_disposition",
            "unresolved_disposition": label == "unresolved_disposition",
            "basis": {
                "review_verdict_label": verdict_label,
                "verdict_stability_label": stability_label,
                "verdict_caveat_override_label": caveat_label,
                "review_readiness_label": readiness_label,
                "review_conclusion_label": conclusion_label,
                "main_supporting_axis": support_axis,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _disposition_distinction_state(
        review_disposition_state: dict,
        verdict_stability_state: dict,
        verdict_caveat_override_state: dict,
        underdetermined_review_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        disposition_label = review_disposition_state.get("review_disposition_label", "unresolved_disposition")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        caveat_label = verdict_caveat_override_state.get("verdict_caveat_override_label", "caveat_balanced_verdict")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")

        conflict_pressure = lane_label == "conflicting_evidence_lanes"
        novelty_pressure = novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        sparse_pressure = under_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"}

        guarded_usable = (
            disposition_label in {"guarded_disposition", "strong_supported_disposition"}
            and stability_label in {"stable_verdict", "mostly_stable_verdict"}
            and caveat_label in {"caveat_light_verdict", "caveat_limited_verdict", "caveat_balanced_verdict"}
            and not conflict_pressure
            and exception_label == "precedent_friendly_case"
        )
        open_question = (
            disposition_label == "open_question_disposition"
            or (sparse_pressure and not conflict_pressure and not guarded_usable)
        )
        unresolved_conflict_or_sparse = conflict_pressure or (stability_label == "highly_provisional_verdict" and sparse_pressure)
        strong_supported = (
            disposition_label == "strong_supported_disposition"
            and stability_label == "stable_verdict"
            and caveat_label == "caveat_light_verdict"
            and not novelty_pressure
            and not conflict_pressure
        )

        if strong_supported:
            distinction = "strong_supported_disposition"
        elif unresolved_conflict_or_sparse:
            distinction = "unresolved_due_to_sparse_or_conflicting_evidence"
        elif guarded_usable:
            distinction = "guarded_but_usable_disposition"
        elif open_question:
            distinction = "open_question_disposition"
        else:
            distinction = "open_question_disposition" if novelty_pressure else "guarded_but_usable_disposition"

        lines = [
            f"Disposition distinction: {distinction}.",
            f"Stability={stability_label}; caveat={caveat_label}; underdetermined={under_label}; lane={lane_label}.",
            f"Exception={exception_label}; novelty={novelty_label}; hybrid={hybrid_label}.",
        ]
        return {
            "disposition_distinction_label": distinction,
            "guarded_but_usable_disposition": distinction == "guarded_but_usable_disposition",
            "open_question_disposition": distinction == "open_question_disposition",
            "unresolved_due_to_sparse_or_conflicting_evidence": distinction == "unresolved_due_to_sparse_or_conflicting_evidence",
            "strong_supported_disposition": distinction == "strong_supported_disposition",
            "basis": {
                "review_disposition_label": disposition_label,
                "verdict_stability_label": stability_label,
                "verdict_caveat_override_label": caveat_label,
                "underdetermined_review_label": under_label,
                "exception_review_label": exception_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _unresolved_disposition_state(
        review_verdict_state: dict,
        verdict_stability_state: dict,
        underdetermined_review_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")

        novelty_unresolved = novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        split_conflict_unresolved = lane_label == "conflicting_evidence_lanes" or under_label == "underdetermined_due_to_split_conflict"
        sparse_unresolved = under_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"}

        weakly_resolved = (
            verdict_label in {"moderate_usable_verdict", "provisional_verdict"}
            and stability_label in {"mostly_stable_verdict", "provisional_verdict"}
            and not split_conflict_unresolved
            and not novelty_unresolved
        )

        if stability_label == "highly_provisional_verdict" and novelty_unresolved:
            label = "unresolved_due_to_novelty"
        elif split_conflict_unresolved:
            label = "unresolved_due_to_split_or_conflict"
        elif stability_label in {"provisional_verdict", "highly_provisional_verdict"} and sparse_unresolved:
            label = "unresolved_due_to_sparse_support"
        elif weakly_resolved:
            label = "weakly_resolved_disposition"
        else:
            label = "weakly_resolved_disposition" if verdict_label == "moderate_usable_verdict" else "unresolved_due_to_sparse_support"

        lines = [
            f"Unresolved posture: {label}.",
            f"Verdict={verdict_label}; stability={stability_label}; underdetermined={under_label}; lane={lane_label}.",
            f"Novelty={novelty_label}; hybrid={hybrid_label}; exception={exception_label}.",
        ]
        return {
            "unresolved_disposition_label": label,
            "unresolved_due_to_novelty": label == "unresolved_due_to_novelty",
            "unresolved_due_to_split_or_conflict": label == "unresolved_due_to_split_or_conflict",
            "unresolved_due_to_sparse_support": label == "unresolved_due_to_sparse_support",
            "weakly_resolved_disposition": label == "weakly_resolved_disposition",
            "basis": {
                "review_verdict_label": verdict_label,
                "verdict_stability_label": stability_label,
                "underdetermined_review_label": under_label,
                "exception_review_label": exception_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_disposition_evidence(
        review_disposition_state: dict,
        disposition_distinction_state: dict,
        unresolved_disposition_state: dict,
        verdict_caveat_override_state: dict,
        operator_verdict_evidence: dict,
    ) -> dict:
        overall = review_disposition_state.get("review_disposition_label", "unresolved_disposition")
        qualifier = review_disposition_state.get("disposition_qualifier", "unresolved")
        distinction = disposition_distinction_state.get("disposition_distinction_label", "open_question_disposition")
        unresolved_label = unresolved_disposition_state.get("unresolved_disposition_label", "unresolved_due_to_sparse_support")
        caveat_pressure = verdict_caveat_override_state.get("primary_caveat", "No dominant caveat beyond routine uncertainty.")
        support_axis = operator_verdict_evidence.get("main_supporting_axis", "no_clear_axis")

        lines = [
            f"Final posture: {overall} ({qualifier}).",
            f"Disposition distinction: {distinction}; unresolved trigger: {unresolved_label}.",
            f"Main caveat pressure: {caveat_pressure}",
            f"Main support axis: {support_axis}.",
        ]
        return {
            "overall_disposition": overall,
            "disposition_qualifier": qualifier,
            "disposition_distinction": distinction,
            "unresolved_trigger": unresolved_label,
            "main_caveat_pressure": caveat_pressure,
            "main_support_axis": support_axis,
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _review_closure_state(
        review_disposition_state: dict,
        disposition_distinction_state: dict,
        unresolved_disposition_state: dict,
        operator_disposition_evidence: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        verdict_stability_state: dict,
        verdict_caveat_override_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
        exception_review_state: dict,
    ) -> dict:
        distinction = disposition_distinction_state.get("disposition_distinction_label", "open_question_disposition")
        unresolved_label = unresolved_disposition_state.get("unresolved_disposition_label", "unresolved_due_to_sparse_support")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        caveat_label = verdict_caveat_override_state.get("verdict_caveat_override_label", "caveat_balanced_verdict")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")

        pending_novelty = novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        pending_split = lane_label == "conflicting_evidence_lanes" or unresolved_label == "unresolved_due_to_split_or_conflict"
        pending_sparse = under_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"} or unresolved_label == "unresolved_due_to_sparse_support"
        unresolved = unresolved_label in {"unresolved_due_to_novelty", "unresolved_due_to_split_or_conflict", "unresolved_due_to_sparse_support"}
        weakly_closed = unresolved_label == "weakly_resolved_disposition" or stability_label in {"mostly_stable_verdict", "provisional_verdict"}

        if distinction == "strong_supported_disposition" and stability_label == "stable_verdict" and caveat_label == "caveat_light_verdict" and not (pending_novelty or pending_split or pending_sparse or unresolved):
            closure_label = "closed_supported_review"
            qualifier = "closed"
        elif distinction == "guarded_but_usable_disposition" and not unresolved and not pending_split:
            closure_label = "guarded_but_usable_review"
            qualifier = "guarded_open"
        elif unresolved or pending_split or pending_novelty or pending_sparse:
            closure_label = "unresolved_review"
            qualifier = "unresolved"
        else:
            closure_label = "still_open_review"
            qualifier = "open"

        pending_reason = "none"
        if pending_novelty:
            pending_reason = "pending_due_to_novelty"
        elif pending_split:
            pending_reason = "pending_due_to_split_conflict"
        elif pending_sparse:
            pending_reason = "pending_due_to_sparse_support"
        elif weakly_closed and closure_label != "closed_supported_review":
            pending_reason = "weakly_closed_review"

        support_axis = operator_disposition_evidence.get("main_support_axis", "no_clear_axis")
        lines = [
            f"Review closure posture: {closure_label} ({qualifier}).",
            f"Pending pressure: {pending_reason}; distinction={distinction}; unresolved={unresolved_label}.",
            f"Verdict={verdict_label}/{stability_label}; readiness={readiness_label}; caveat={caveat_label}; support_axis={support_axis}.",
        ]
        if exception_label != "precedent_friendly_case":
            lines.append(f"Exception pressure remains active ({exception_label}); keep closure bounded.")

        return {
            "review_closure_label": closure_label,
            "closure_qualifier": qualifier,
            "closed_supported_review": closure_label == "closed_supported_review",
            "guarded_but_usable_review": closure_label == "guarded_but_usable_review",
            "still_open_review": closure_label == "still_open_review",
            "unresolved_review": closure_label == "unresolved_review",
            "pending_due_to_novelty": pending_reason == "pending_due_to_novelty",
            "pending_due_to_split_conflict": pending_reason == "pending_due_to_split_conflict",
            "pending_due_to_sparse_support": pending_reason == "pending_due_to_sparse_support",
            "weakly_closed_review": pending_reason == "weakly_closed_review",
            "pending_reason": pending_reason,
            "basis": {
                "disposition_distinction_label": distinction,
                "unresolved_disposition_label": unresolved_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "verdict_stability_label": stability_label,
                "verdict_caveat_override_label": caveat_label,
                "underdetermined_review_label": under_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
                "exception_review_label": exception_label,
            },
            "compact_lines": lines[:4],
        }

    @staticmethod
    def _operator_review_closure_evidence(
        review_closure_state: dict,
        review_disposition_state: dict,
        unresolved_disposition_state: dict,
        operator_disposition_evidence: dict,
        review_verdict_state: dict,
        operator_verdict_evidence: dict,
    ) -> dict:
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        qualifier = review_closure_state.get("closure_qualifier", "open")
        pending_reason = review_closure_state.get("pending_reason", "none")
        support_axis = operator_disposition_evidence.get("main_support_axis") or operator_verdict_evidence.get("main_supporting_axis", "no_clear_axis")
        disposition = review_disposition_state.get("review_disposition_label", "unresolved_disposition")
        unresolved = unresolved_disposition_state.get("unresolved_disposition_label", "unresolved_due_to_sparse_support")
        verdict = review_verdict_state.get("review_verdict_label", "provisional_verdict")

        lines = [
            f"Closure posture: {closure_label} ({qualifier}).",
            f"Main pending pressure: {pending_reason}; unresolved trigger: {unresolved}.",
            f"Support axis: {support_axis}; disposition={disposition}; verdict={verdict}.",
        ]

        return {
            "overall_closure_posture": closure_label,
            "closure_qualifier": qualifier,
            "main_pending_pressure": pending_reason,
            "main_support_axis": support_axis,
            "disposition_label": disposition,
            "unresolved_trigger": unresolved,
            "review_verdict_label": verdict,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _review_resolution_state(
        review_closure_state: dict,
        operator_review_closure_evidence: dict,
        review_disposition_state: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        verdict_stability_state: dict,
        verdict_caveat_override_state: dict,
        underdetermined_review_state: dict,
        unresolved_disposition_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        pending_reason = review_closure_state.get("pending_reason", "pending_due_to_sparse_support")
        disposition_label = review_disposition_state.get("review_disposition_label", "unresolved_disposition")
        unresolved_label = unresolved_disposition_state.get("unresolved_disposition_label", "unresolved_due_to_sparse_support")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        caveat_label = verdict_caveat_override_state.get("verdict_caveat_override_label", "caveat_balanced_verdict")
        under_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")

        pending_active = pending_reason != "none"
        novelty_partial = novelty_label == "high_novelty" or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        split_partial = lane_label == "conflicting_evidence_lanes" or unresolved_label == "unresolved_due_to_split_or_conflict"
        sparse_partial = under_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"} or unresolved_label == "unresolved_due_to_sparse_support"
        weak_resolution = verdict_label in {"moderate_usable_verdict", "provisional_verdict"} or stability_label in {"mostly_stable_verdict", "provisional_verdict"}

        resolved = (
            closure_label == "closed_supported_review"
            and not pending_active
            and stability_label == "stable_verdict"
            and caveat_label == "caveat_light_verdict"
            and exception_label == "precedent_friendly_case"
            and not (novelty_partial or split_partial or sparse_partial)
        )
        unresolved = closure_label == "unresolved_review" or unresolved_label in {
            "unresolved_due_to_novelty",
            "unresolved_due_to_split_or_conflict",
            "unresolved_due_to_sparse_support",
        }
        closed_for_now = (
            not resolved
            and not unresolved
            and (
                closure_label in {"guarded_but_usable_review", "still_open_review"}
                or pending_active
                or caveat_label in {"caveat_guarded_verdict", "caveat_heavy_override"}
            )
        )
        partially_resolved = not resolved and not unresolved and (
            novelty_partial
            or split_partial
            or sparse_partial
            or weak_resolution
            or disposition_label in {"open_question_disposition", "guarded_disposition"}
        )

        if resolved:
            resolution_label = "resolved_review"
        elif unresolved:
            resolution_label = "unresolved_review"
        elif partially_resolved:
            resolution_label = "partially_resolved_review"
        else:
            resolution_label = "closed_for_now_review"

        lines = [
            f"Review resolution posture: {resolution_label}.",
            f"Closure={closure_label}; pending={pending_reason}; verdict={verdict_label}/{stability_label}; caveat={caveat_label}.",
            f"Partial pressure: novelty={novelty_partial}, split={split_partial}, sparse={sparse_partial}, weak={weak_resolution}.",
        ]
        return {
            "review_resolution_label": resolution_label,
            "resolved_review": resolution_label == "resolved_review",
            "closed_for_now_review": resolution_label == "closed_for_now_review",
            "partially_resolved_review": resolution_label == "partially_resolved_review",
            "unresolved_review": resolution_label == "unresolved_review",
            "partially_resolved_due_to_novelty": novelty_partial and resolution_label == "partially_resolved_review",
            "partially_resolved_due_to_split_or_conflict": split_partial and resolution_label == "partially_resolved_review",
            "partially_resolved_due_to_sparse_support": sparse_partial and resolution_label == "partially_resolved_review",
            "weakly_resolved_review": weak_resolution and resolution_label in {"partially_resolved_review", "closed_for_now_review"},
            "main_pending_pressure": pending_reason,
            "main_support_axis": operator_review_closure_evidence.get("main_support_axis", "no_clear_axis"),
            "basis": {
                "review_closure_label": closure_label,
                "review_disposition_label": disposition_label,
                "unresolved_disposition_label": unresolved_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "verdict_stability_label": stability_label,
                "verdict_caveat_override_label": caveat_label,
                "underdetermined_review_label": under_label,
                "exception_review_label": exception_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _review_finalization_state(
        review_resolution_state: dict,
        operator_review_resolution_evidence: dict,
        review_closure_state: dict,
        review_disposition_state: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        verdict_stability_state: dict,
        underdetermined_review_state: dict,
        exception_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        resolution_label = review_resolution_state.get("review_resolution_label", "closed_for_now_review")
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        pending_reason = review_closure_state.get("pending_reason", "pending_due_to_sparse_support")
        disposition_label = review_disposition_state.get("review_disposition_label", "unresolved_disposition")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        stability_label = verdict_stability_state.get("verdict_stability_label", "provisional_verdict")
        underdetermined_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        exception_label = exception_review_state.get("exception_review_label", "precedent_friendly_case")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")

        blocked_by_revisitable_pressure = resolution_label in {"closed_for_now_review", "partially_resolved_review"} or pending_reason in {
            "pending_due_to_split_conflict",
            "pending_due_to_sparse_support",
            "pending_due_to_novelty",
            "pending_due_to_verdict_caveat_pressure",
            "pending_due_to_provisional_verdict",
            "pending_due_to_open_scope",
            "weakly_closed_review",
        }
        blocked_by_novelty = novelty_label == "high_novelty" or hybrid_label in {
            "two_family_hybrid",
            "mixed_family_pull",
            "unstable_family_identity",
        }
        blocked_by_split_or_conflict = lane_label == "conflicting_evidence_lanes" or exception_label in {
            "split_precedent_exception_case",
            "conflicting_analog_exception_case",
        }
        blocked_by_sparse_support = underdetermined_label in {
            "underdetermined_due_to_sparse_precedent",
            "underdetermined_due_to_novelty",
        }
        weakly_finalizable_review = (
            verdict_label in {"moderate_usable_verdict", "provisional_verdict"}
            or stability_label in {"mostly_stable_verdict", "provisional_verdict"}
            or pending_reason == "weakly_closed_review"
            or readiness_label == "low_review_readiness"
        )
        blocked = blocked_by_revisitable_pressure or blocked_by_novelty or blocked_by_split_or_conflict or blocked_by_sparse_support

        finalized_review = (
            resolution_label == "resolved_review"
            and closure_label == "closed_supported_review"
            and not blocked
            and not weakly_finalizable_review
        )
        unresolved_review = resolution_label == "unresolved_review" or disposition_label == "unresolved_disposition"
        resolved_for_now_review = (
            not finalized_review
            and not unresolved_review
            and resolution_label in {"closed_for_now_review", "partially_resolved_review"}
        )
        not_yet_finalized_review = not finalized_review and not unresolved_review and not resolved_for_now_review

        if finalized_review:
            finalization_label = "finalized_review"
        elif unresolved_review:
            finalization_label = "unresolved_review"
        elif resolved_for_now_review:
            finalization_label = "resolved_for_now_review"
        else:
            finalization_label = "not_yet_finalized_review"

        blocking_label = AuraliteReportingService._settlement_blocking_label(
            blocked_by_revisitable_pressure=blocked_by_revisitable_pressure,
            blocked_by_novelty=blocked_by_novelty,
            blocked_by_split_or_conflict=blocked_by_split_or_conflict,
            blocked_by_sparse_support=blocked_by_sparse_support,
            weakly_settleable_review=weakly_finalizable_review,
        )

        support_axis = operator_review_resolution_evidence.get("main_support_axis", "no_clear_axis")
        lines = [
            f"Review finalization posture: {finalization_label}.",
            f"Resolution={resolution_label}; closure={closure_label}; pending={pending_reason}; stability={stability_label}.",
            f"Blocking={blocking_label}; support_axis={support_axis}.",
        ]

        return {
            "review_finalization_label": finalization_label,
            "finalized_review": finalized_review,
            "resolved_for_now_review": resolved_for_now_review,
            "not_yet_finalized_review": not_yet_finalized_review,
            "unresolved_review": unresolved_review,
            "blocked_by_revisitable_pressure": blocked_by_revisitable_pressure,
            "blocked_by_novelty": blocked_by_novelty,
            "blocked_by_split_or_conflict": blocked_by_split_or_conflict,
            "blocked_by_sparse_support": blocked_by_sparse_support,
            "weakly_finalizable_review": weakly_finalizable_review,
            "blocking_label": blocking_label,
            "main_pending_pressure": pending_reason,
            "main_support_axis": support_axis,
            "basis": {
                "review_resolution_label": resolution_label,
                "review_closure_label": closure_label,
                "review_disposition_label": disposition_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "verdict_stability_label": stability_label,
                "underdetermined_review_label": underdetermined_label,
                "exception_review_label": exception_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _review_settlement_state(
        review_finalization_state: dict,
        operator_review_finalization_evidence: dict,
        review_resolution_state: dict,
        review_closure_state: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        finalization_label = review_finalization_state.get("review_finalization_label", "not_yet_finalized_review")
        resolution_label = review_resolution_state.get("review_resolution_label", "closed_for_now_review")
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        pending_reason = review_closure_state.get("pending_reason", "pending_due_to_sparse_support")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        underdetermined_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")

        blocked_by_revisitable_pressure = bool(review_finalization_state.get("blocked_by_revisitable_pressure", False))
        blocked_by_novelty = bool(review_finalization_state.get("blocked_by_novelty", False))
        blocked_by_split_or_conflict = bool(review_finalization_state.get("blocked_by_split_or_conflict", False))
        blocked_by_sparse_support = bool(review_finalization_state.get("blocked_by_sparse_support", False))
        weakly_settleable_review = bool(review_finalization_state.get("weakly_finalizable_review", False))
        unresolved_review = bool(review_finalization_state.get("unresolved_review", False) or resolution_label == "unresolved_review")

        settled_review = (
            finalization_label == "finalized_review"
            and not (blocked_by_revisitable_pressure or blocked_by_novelty or blocked_by_split_or_conflict or blocked_by_sparse_support)
            and not weakly_settleable_review
        )
        finalized_for_now_review = (
            not settled_review
            and not unresolved_review
            and finalization_label in {"resolved_for_now_review", "not_yet_finalized_review"}
            and (
                blocked_by_revisitable_pressure
                or review_finalization_state.get("resolved_for_now_review", False)
                or resolution_label in {"closed_for_now_review", "partially_resolved_review"}
            )
        )
        not_yet_settled_review = not settled_review and not unresolved_review and not finalized_for_now_review

        if settled_review:
            settlement_label = "settled_review"
        elif unresolved_review:
            settlement_label = "unresolved_review"
        elif finalized_for_now_review:
            settlement_label = "finalized_for_now_review"
        else:
            settlement_label = "not_yet_settled_review"

        blocking_label = AuraliteReportingService._settlement_blocking_label(
            blocked_by_revisitable_pressure=blocked_by_revisitable_pressure,
            blocked_by_novelty=blocked_by_novelty,
            blocked_by_split_or_conflict=blocked_by_split_or_conflict,
            blocked_by_sparse_support=blocked_by_sparse_support,
            weakly_settleable_review=weakly_settleable_review,
        )

        support_axis = review_finalization_state.get("main_support_axis") or operator_review_finalization_evidence.get("main_support_axis", "no_clear_axis")
        lines = [
            f"Review settlement posture: {settlement_label}.",
            f"Finalization={finalization_label}; resolution={resolution_label}; closure={closure_label}; pending={pending_reason}.",
            f"Blocking={blocking_label}; support_axis={support_axis}; verdict={verdict_label}; readiness={readiness_label}.",
        ]
        blocking_triggers = [
            label
            for active, label in (
                (blocked_by_revisitable_pressure, "blocked_by_revisitable_pressure"),
                (blocked_by_novelty, "blocked_by_novelty"),
                (blocked_by_split_or_conflict, "blocked_by_split_or_conflict"),
                (blocked_by_sparse_support, "blocked_by_sparse_support"),
                (weakly_settleable_review, "weakly_settleable_review"),
            )
            if active
        ]
        if not blocking_triggers:
            blocking_triggers = ["not_blocked"]
        return {
            "review_settlement_label": settlement_label,
            "settled_review": settled_review,
            "finalized_for_now_review": finalized_for_now_review,
            "not_yet_settled_review": not_yet_settled_review,
            "unresolved_review": unresolved_review,
            "blocked_by_revisitable_pressure": blocked_by_revisitable_pressure,
            "blocked_by_novelty": blocked_by_novelty,
            "blocked_by_split_or_conflict": blocked_by_split_or_conflict,
            "blocked_by_sparse_support": blocked_by_sparse_support,
            "weakly_settleable_review": weakly_settleable_review,
            "main_blocking_pressure": blocking_label,
            "blocking_triggers": blocking_triggers,
            "main_pending_pressure": pending_reason,
            "main_support_axis": support_axis,
            "basis": {
                "review_finalization_label": finalization_label,
                "review_resolution_label": resolution_label,
                "review_closure_label": closure_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "underdetermined_review_label": underdetermined_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_review_resolution_evidence(
        review_resolution_state: dict,
        operator_review_closure_evidence: dict,
    ) -> dict:
        posture = review_resolution_state.get("review_resolution_label", "closed_for_now_review")
        pending = review_resolution_state.get("main_pending_pressure", "pending_due_to_sparse_support")
        support_axis = review_resolution_state.get("main_support_axis") or operator_review_closure_evidence.get("main_support_axis", "no_clear_axis")
        if review_resolution_state.get("partially_resolved_due_to_novelty", False):
            qualifier = "partial_due_to_novelty"
        elif review_resolution_state.get("partially_resolved_due_to_split_or_conflict", False):
            qualifier = "partial_due_to_split_conflict"
        elif review_resolution_state.get("partially_resolved_due_to_sparse_support", False):
            qualifier = "partial_due_to_sparse_support"
        elif review_resolution_state.get("weakly_resolved_review", False):
            qualifier = "weakly_resolved"
        else:
            qualifier = "clean_resolution" if posture == "resolved_review" else "bounded_resolution"

        lines = [
            f"Resolution posture: {posture} ({qualifier}).",
            f"Pending pressure: {pending}.",
            f"Support axis: {support_axis}.",
        ]
        return {
            "overall_resolution_posture": posture,
            "resolution_qualifier": qualifier,
            "main_pending_pressure": pending,
            "main_support_axis": support_axis,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _settlement_blocking_label(
        blocked_by_revisitable_pressure: bool,
        blocked_by_novelty: bool,
        blocked_by_split_or_conflict: bool,
        blocked_by_sparse_support: bool,
        weakly_settleable_review: bool,
    ) -> str:
        if blocked_by_revisitable_pressure:
            return "blocked_by_revisitable_pressure"
        if blocked_by_novelty:
            return "blocked_by_novelty"
        if blocked_by_split_or_conflict:
            return "blocked_by_split_or_conflict"
        if blocked_by_sparse_support:
            return "blocked_by_sparse_support"
        if weakly_settleable_review:
            return "weakly_settleable_review"
        return "not_blocked"

    @staticmethod
    def _operator_review_finalization_evidence(
        review_finalization_state: dict,
        operator_review_resolution_evidence: dict,
    ) -> dict:
        posture = review_finalization_state.get("review_finalization_label", "not_yet_finalized_review")
        blocking_label = review_finalization_state.get("blocking_label", "not_blocked")
        pending = review_finalization_state.get("main_pending_pressure", "none")
        support_axis = review_finalization_state.get("main_support_axis") or operator_review_resolution_evidence.get(
            "main_support_axis",
            "no_clear_axis",
        )
        lines = [
            f"Finalization posture: {posture}.",
            f"Main blocker: {blocking_label}; pending pressure: {pending}.",
            f"Main support axis: {support_axis}.",
        ]
        finalized_but_revisitable = posture == "resolved_for_now_review" or blocking_label in {
            "blocked_by_revisitable_pressure",
            "weakly_settleable_review",
        }
        return {
            "overall_finalization_posture": posture,
            "finalization_qualifier": posture,
            "finalized_but_revisitable": finalized_but_revisitable,
            "settled_vs_finalized_for_now": (
                "finalized_for_now_review" if finalized_but_revisitable else ("settled_review" if posture == "finalized_review" else "not_yet_settled_review")
            ),
            "main_blocking_pressure": blocking_label,
            "main_pending_pressure": pending,
            "main_support_axis": support_axis,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_review_settlement_evidence(
        review_settlement_state: dict,
        review_finalization_state: dict,
        operator_review_finalization_evidence: dict,
    ) -> dict:
        posture = review_settlement_state.get("review_settlement_label", "not_yet_settled_review")
        blocking = review_settlement_state.get("main_blocking_pressure", "not_blocked")
        pending = review_settlement_state.get("main_pending_pressure", "none")
        support_axis = review_settlement_state.get("main_support_axis") or operator_review_finalization_evidence.get("main_support_axis", "no_clear_axis")
        finalization = review_finalization_state.get("review_finalization_label", "not_yet_finalized_review")
        lines = [
            f"Settlement posture: {posture}.",
            f"Settlement blocker: {blocking}; pending pressure: {pending}.",
            f"Support axis: {support_axis}; finalization={finalization}.",
        ]
        return {
            "overall_settlement_posture": posture,
            "settlement_qualifier": posture,
            "main_blocking_pressure": blocking,
            "main_pending_pressure": pending,
            "main_support_axis": support_axis,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _review_archival_state(
        review_settlement_state: dict,
        operator_review_settlement_evidence: dict,
        review_finalization_state: dict,
        review_resolution_state: dict,
        review_closure_state: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        settlement_label = review_settlement_state.get("review_settlement_label", "not_yet_settled_review")
        finalization_label = review_finalization_state.get("review_finalization_label", "not_yet_finalized_review")
        resolution_label = review_resolution_state.get("review_resolution_label", "closed_for_now_review")
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        pending_reason = review_closure_state.get("pending_reason", "pending_due_to_sparse_support")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        underdetermined_label = underdetermined_review_state.get(
            "underdetermined_review_label", "underdetermined_due_to_sparse_precedent"
        )
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        stability_label = (review_verdict_state.get("basis") or {}).get("verdict_stability_label", "provisional_verdict")

        blocked_by_reopenable_pressure = bool(
            review_settlement_state.get("blocked_by_revisitable_pressure", False)
            or finalization_label == "resolved_for_now_review"
            or resolution_label in {"closed_for_now_review", "partially_resolved_review"}
            or closure_label != "closed_supported_review"
            or pending_reason != "none"
            or verdict_label == "provisional_verdict"
            or stability_label in {"provisional_verdict", "mostly_stable_verdict"}
            or readiness_label == "low_review_readiness"
        )
        blocked_by_novelty = bool(
            review_settlement_state.get("blocked_by_novelty", False)
            or novelty_label == "high_novelty"
            or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        )
        blocked_by_split_or_conflict = bool(
            review_settlement_state.get("blocked_by_split_or_conflict", False)
            or underdetermined_label == "underdetermined_due_to_split_conflict"
            or lane_label == "conflicting_evidence_lanes"
        )
        blocked_by_sparse_support = bool(
            review_settlement_state.get("blocked_by_sparse_support", False)
            or underdetermined_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"}
        )
        weakly_archivable_review = bool(
            review_settlement_state.get("weakly_settleable_review", False)
            or verdict_label in {"moderate_usable_verdict", "provisional_verdict"}
            or stability_label in {"mostly_stable_verdict", "provisional_verdict"}
        )
        unresolved_review = bool(
            review_settlement_state.get("unresolved_review", False) or review_resolution_state.get("unresolved_review", False)
        )
        blocked = blocked_by_reopenable_pressure or blocked_by_novelty or blocked_by_split_or_conflict or blocked_by_sparse_support
        archivable_review = (
            settlement_label == "settled_review"
            and not unresolved_review
            and not blocked
            and not weakly_archivable_review
        )
        settled_for_now_review = (
            not archivable_review
            and not unresolved_review
            and (
                settlement_label == "finalized_for_now_review"
                or blocked_by_reopenable_pressure
                or weakly_archivable_review
                or finalization_label == "resolved_for_now_review"
            )
        )
        not_yet_archivable_review = not archivable_review and not unresolved_review and not settled_for_now_review
        archival_label = (
            "archivable_review"
            if archivable_review
            else ("unresolved_review" if unresolved_review else ("settled_for_now_review" if settled_for_now_review else "not_yet_archivable_review"))
        )
        blocking_label = AuraliteReportingService._settlement_blocking_label(
            blocked_by_revisitable_pressure=blocked_by_reopenable_pressure,
            blocked_by_novelty=blocked_by_novelty,
            blocked_by_split_or_conflict=blocked_by_split_or_conflict,
            blocked_by_sparse_support=blocked_by_sparse_support,
            weakly_settleable_review=weakly_archivable_review,
        )
        if blocking_label == "blocked_by_revisitable_pressure":
            blocking_label = "blocked_by_reopenable_pressure"
        elif blocking_label == "weakly_settleable_review":
            blocking_label = "weakly_archivable_review"
        support_axis = review_settlement_state.get("main_support_axis") or operator_review_settlement_evidence.get(
            "main_support_axis", "no_clear_axis"
        )
        lines = [
            f"Review archival posture: {archival_label}.",
            f"Settlement={settlement_label}; finalization={finalization_label}; resolution={resolution_label}; pending={pending_reason}.",
            f"Archival blocker={blocking_label}; support_axis={support_axis}; closure={closure_label}.",
        ]
        blocking_triggers = [
            label
            for active, label in (
                (blocked_by_reopenable_pressure, "blocked_by_reopenable_pressure"),
                (blocked_by_novelty, "blocked_by_novelty"),
                (blocked_by_split_or_conflict, "blocked_by_split_or_conflict"),
                (blocked_by_sparse_support, "blocked_by_sparse_support"),
                (weakly_archivable_review, "weakly_archivable_review"),
            )
            if active
        ]
        if not blocking_triggers:
            blocking_triggers = ["not_blocked"]
        return {
            "review_archival_label": archival_label,
            "archivable_review": archivable_review,
            "settled_for_now_review": settled_for_now_review,
            "not_yet_archivable_review": not_yet_archivable_review,
            "unresolved_review": unresolved_review,
            "blocked_by_reopenable_pressure": blocked_by_reopenable_pressure,
            "blocked_by_novelty": blocked_by_novelty,
            "blocked_by_split_or_conflict": blocked_by_split_or_conflict,
            "blocked_by_sparse_support": blocked_by_sparse_support,
            "weakly_archivable_review": weakly_archivable_review,
            "main_blocking_pressure": blocking_label,
            "blocking_triggers": blocking_triggers,
            "main_pending_pressure": pending_reason,
            "main_support_axis": support_axis,
            "basis": {
                "review_settlement_label": settlement_label,
                "review_finalization_label": finalization_label,
                "review_resolution_label": resolution_label,
                "review_closure_label": closure_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "underdetermined_review_label": underdetermined_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_review_archival_evidence(
        review_archival_state: dict,
        review_settlement_state: dict,
        operator_review_settlement_evidence: dict,
    ) -> dict:
        posture = review_archival_state.get("review_archival_label", "not_yet_archivable_review")
        blocking = review_archival_state.get("main_blocking_pressure", "not_blocked")
        pending = review_archival_state.get("main_pending_pressure", "none")
        support_axis = review_archival_state.get("main_support_axis") or operator_review_settlement_evidence.get(
            "main_support_axis", "no_clear_axis"
        )
        settlement = review_settlement_state.get("review_settlement_label", "not_yet_settled_review")
        lines = [
            f"Archival posture: {posture}.",
            f"Archival blocker: {blocking}; pending pressure: {pending}.",
            f"Support axis: {support_axis}; settlement={settlement}.",
        ]
        return {
            "overall_archival_posture": posture,
            "archival_qualifier": posture,
            "main_blocking_pressure": blocking,
            "main_pending_pressure": pending,
            "main_support_axis": support_axis,
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _first_active_blocking_label(ordered_pairs: list[tuple[bool, str]], default_label: str = "not_blocked") -> str:
        for active, label in ordered_pairs:
            if active:
                return label
        return default_label

    def _review_preservation_state(
        review_archival_state: dict,
        operator_review_archival_evidence: dict,
        review_settlement_state: dict,
        review_finalization_state: dict,
        review_resolution_state: dict,
        review_closure_state: dict,
        review_verdict_state: dict,
        review_readiness_state: dict,
        underdetermined_review_state: dict,
        scenario_novelty_state: dict,
        hybrid_family_state: dict,
        evidence_lane_state: dict,
    ) -> dict:
        archival_label = review_archival_state.get("review_archival_label", "not_yet_archivable_review")
        settlement_label = review_settlement_state.get("review_settlement_label", "not_yet_settled_review")
        finalization_label = review_finalization_state.get("review_finalization_label", "not_yet_finalized_review")
        resolution_label = review_resolution_state.get("review_resolution_label", "closed_for_now_review")
        closure_label = review_closure_state.get("review_closure_label", "still_open_review")
        pending_reason = review_closure_state.get("pending_reason", "pending_due_to_sparse_support")
        verdict_label = review_verdict_state.get("review_verdict_label", "provisional_verdict")
        readiness_label = review_readiness_state.get("review_readiness_label", "low_review_readiness")
        underdetermined_label = underdetermined_review_state.get("underdetermined_review_label", "underdetermined_due_to_sparse_precedent")
        novelty_label = scenario_novelty_state.get("novelty_label", "moderate_novelty")
        hybrid_label = hybrid_family_state.get("hybrid_label", "weak_single_family_anchor")
        lane_label = evidence_lane_state.get("evidence_lane_label", "sparse_ambiguous_evidence_lanes")
        stability_label = (review_verdict_state.get("basis") or {}).get("verdict_stability_label", "provisional_verdict")
        archival_blocking = review_archival_state.get("main_blocking_pressure", "not_blocked")

        unresolved_review = bool(
            review_archival_state.get("unresolved_review", False)
            or review_settlement_state.get("unresolved_review", False)
            or review_resolution_state.get("unresolved_review", False)
        )
        blocked_by_reopenable_pressure = bool(
            review_archival_state.get("blocked_by_reopenable_pressure", False)
            or archival_blocking == "blocked_by_reopenable_pressure"
            or finalization_label == "resolved_for_now_review"
            or resolution_label in {"closed_for_now_review", "partially_resolved_review"}
            or closure_label != "closed_supported_review"
            or pending_reason != "none"
            or verdict_label in {"provisional_verdict", "moderate_usable_verdict"}
            or stability_label in {"provisional_verdict", "mostly_stable_verdict"}
            or readiness_label == "low_review_readiness"
        )
        blocked_by_novelty = bool(
            review_archival_state.get("blocked_by_novelty", False)
            or novelty_label == "high_novelty"
            or hybrid_label in {"two_family_hybrid", "mixed_family_pull", "unstable_family_identity"}
        )
        blocked_by_split_or_conflict = bool(
            review_archival_state.get("blocked_by_split_or_conflict", False)
            or underdetermined_label == "underdetermined_due_to_split_conflict"
            or lane_label == "conflicting_evidence_lanes"
        )
        blocked_by_sparse_support = bool(
            review_archival_state.get("blocked_by_sparse_support", False)
            or underdetermined_label in {"underdetermined_due_to_sparse_precedent", "underdetermined_due_to_novelty"}
            or lane_label == "sparse_ambiguous_evidence_lanes"
        )
        weakly_preservable_review = bool(
            review_archival_state.get("weakly_archivable_review", False)
            or review_settlement_state.get("weakly_settleable_review", False)
            or verdict_label == "moderate_usable_verdict"
            or stability_label == "mostly_stable_verdict"
        )
        blocked = blocked_by_reopenable_pressure or blocked_by_novelty or blocked_by_split_or_conflict or blocked_by_sparse_support
        preservable_review = bool(
            archival_label == "archivable_review"
            and settlement_label == "settled_review"
            and not unresolved_review
            and not blocked
            and not weakly_preservable_review
        )
        archivable_for_now_review = bool(
            not preservable_review
            and not unresolved_review
            and (
                archival_label == "settled_for_now_review"
                or settlement_label == "finalized_for_now_review"
                or blocked_by_reopenable_pressure
                or weakly_preservable_review
            )
        )
        not_yet_preservable_review = not preservable_review and not unresolved_review and not archivable_for_now_review
        preservation_label = (
            "preservable_review"
            if preservable_review
            else ("unresolved_review" if unresolved_review else ("archivable_for_now_review" if archivable_for_now_review else "not_yet_preservable_review"))
        )
        blocking_label = AuraliteReportingService._first_active_blocking_label([
            (blocked_by_reopenable_pressure, "blocked_by_reopenable_pressure"),
            (blocked_by_novelty, "blocked_by_novelty"),
            (blocked_by_split_or_conflict, "blocked_by_split_or_conflict"),
            (blocked_by_sparse_support, "blocked_by_sparse_support"),
            (weakly_preservable_review, "weakly_preservable_review"),
        ])
        support_axis = review_archival_state.get("main_support_axis") or operator_review_archival_evidence.get("main_support_axis", "no_clear_axis")
        lines = [
            f"Review preservation posture: {preservation_label}.",
            f"Preservation blocker={blocking_label}; pending={pending_reason}; support_axis={support_axis}.",
            f"Archival={archival_label}; settlement={settlement_label}; finalization={finalization_label}; resolution={resolution_label}.",
        ]
        return {
            "review_preservation_label": preservation_label,
            "preservable_review": preservable_review,
            "archivable_for_now_review": archivable_for_now_review,
            "not_yet_preservable_review": not_yet_preservable_review,
            "unresolved_review": unresolved_review,
            "blocked_by_reopenable_pressure": blocked_by_reopenable_pressure,
            "blocked_by_novelty": blocked_by_novelty,
            "blocked_by_split_or_conflict": blocked_by_split_or_conflict,
            "blocked_by_sparse_support": blocked_by_sparse_support,
            "weakly_preservable_review": weakly_preservable_review,
            "main_blocking_pressure": blocking_label,
            "main_pending_pressure": pending_reason,
            "main_support_axis": support_axis,
            "basis": {
                "review_archival_label": archival_label,
                "review_settlement_label": settlement_label,
                "review_finalization_label": finalization_label,
                "review_resolution_label": resolution_label,
                "review_closure_label": closure_label,
                "review_verdict_label": verdict_label,
                "review_readiness_label": readiness_label,
                "underdetermined_review_label": underdetermined_label,
                "novelty_label": novelty_label,
                "hybrid_label": hybrid_label,
                "evidence_lane_label": lane_label,
            },
            "compact_lines": lines[:3],
        }

    @staticmethod
    def _operator_review_preservation_evidence(
        review_preservation_state: dict,
        review_archival_state: dict,
        operator_review_archival_evidence: dict,
    ) -> dict:
        posture = review_preservation_state.get("review_preservation_label", "not_yet_preservable_review")
        blocking = review_preservation_state.get("main_blocking_pressure", "not_blocked")
